// notes/dsa.js — TOPIC_CONTENT entries for the dsa phase
Object.assign(TOPIC_CONTENT, {
  "dsa_complexity": "<main>\n  <h1>Time & Space Complexity</h1>\n    <div class=\"roadmap-wrap\">\n    <h2 class=\"roadmap-title\">What we'll cover</h2>\n    <div class=\"roadmap-grid\">\n      <div class=\"rm-item rm-done\" data-target=\"cx-ladder\" role=\"button\" tabindex=\"0\"><span class=\"rm-num\">01</span><div class=\"rm-text\"><span class=\"rm-label\">The Complexity Ladder</span><span class=\"rm-sub\">O(1) \u2192 O(log n) \u2192 O(n) \u2192 O(n\u00b2) \u2192 O(2\u207f)</span></div></div>\n      <div class=\"rm-item rm-done\" data-target=\"cx-rules\" role=\"button\" tabindex=\"0\"><span class=\"rm-num\">02</span><div class=\"rm-text\"><span class=\"rm-label\">Big O Rules</span><span class=\"rm-sub\">Drop constants, drop lower terms, multiple inputs</span></div></div>\n      <div class=\"rm-item rm-done\" data-target=\"cx-space\" role=\"button\" tabindex=\"0\"><span class=\"rm-num\">03</span><div class=\"rm-text\"><span class=\"rm-label\">Space Complexity</span><span class=\"rm-sub\">In-place vs new structure, recursion stack</span></div></div>\n      <div class=\"rm-item rm-done\" data-target=\"cx-amortized\" role=\"button\" tabindex=\"0\"><span class=\"rm-num\">04</span><div class=\"rm-text\"><span class=\"rm-label\">Amortized Complexity</span><span class=\"rm-sub\">list.append(), dict collisions, dynamic arrays</span></div></div>\n      <div class=\"rm-item rm-done\" data-target=\"cx-builtins\" role=\"button\" tabindex=\"0\"><span class=\"rm-num\">05</span><div class=\"rm-text\"><span class=\"rm-label\">Python Built-ins Reference</span><span class=\"rm-sub\">Every operation you'll use \u2014 its actual cost</span></div></div>\n      <div class=\"rm-item rm-done\" data-target=\"cx-framework\" role=\"button\" tabindex=\"0\"><span class=\"rm-num\">06</span><div class=\"rm-text\"><span class=\"rm-label\">Interview Analysis Framework</span><span class=\"rm-sub\">3 steps \u2014 apply on every problem</span></div></div>\n    </div>\n  </div>\n\n  <div class=\"panel\">\n    <h2>Revision</h2>\n    <ol>\n      <li><strong>Big O = growth rate, not clock time.</strong> Drop constants, drop lower terms. O(2n) \u2192 O(n). O(n\u00b2 + n) \u2192 O(n\u00b2).</li>\n      <li><strong>Ladder (fast \u2192 slow):</strong> O(1) \u2192 O(log n) \u2192 O(n) \u2192 O(n log n) \u2192 O(n\u00b2) \u2192 O(2\u207f).</li>\n      <li><strong>Multiple inputs = multiple variables:</strong> O(n + m), not O(n). n and m are different arrays.</li>\n      <li><strong>Hidden inner cost trap:</strong> one loop doesn't mean O(n). If the body does O(n) work (list scan, .sort()), total = O(n\u00b2).</li>\n      <li><strong>in list = O(n). in set/dict = O(1).</strong> Swapping list \u2192 set is the most common interview fix: O(n\u00b2) \u2192 O(n).</li>\n      <li><strong>list.append() = O(1) amortized.</strong> Resizes rarely (1\u21922\u21924\u21928...), spread over n appends = O(1) each.</li>\n      <li><strong>dict lookup = O(1) average, O(n) worst.</strong> Worst only with all keys colliding (broken __hash__). Say O(1).</li>\n      <li><strong>Recursion stack = O(depth).</strong> Linear recursion = O(n). Binary search recursion = O(log n).</li>\n      <li><strong>3-step interview framework:</strong> Count loops \u2192 Check body \u2192 Apply rules + state BOTH time AND space.</li>\n      <li><strong>sorted() = O(n log n).</strong> len() = O(1). list[i] = O(1). list.insert(0,x) = O(n).</li>\n    </ol>\n  </div>\n\n  <!-- \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 1. LADDER \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 -->\n  <h2 id=\"cx-ladder\"><span class=\"num\">01</span>The Complexity Ladder</h2>\n\n  <div class=\"callout def\">\n    <span class=\"label\">Definition \u2014 Big O Notation</span>\n    <p>Big O describes how the runtime or memory usage <strong>grows</strong> as input size grows \u2014 not the actual clock time. At scale, constants and smaller terms become irrelevant. Only the dominant term matters. O(2n + 100) and O(n) are the same class: both grow linearly.</p>\n  </div>\n\n  <figure>\n    <svg viewBox=\"0 0 700 200\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"Inter, sans-serif\">\n      <text x=\"350\" y=\"20\" text-anchor=\"middle\" font-size=\"13\" font-weight=\"700\" fill=\"#191B27\">Complexity Ladder \u2014 fastest to slowest</text>\n      <defs>\n        <linearGradient id=\"cxgrad\" x1=\"0\" y1=\"0\" x2=\"1\" y2=\"0\">\n          <stop offset=\"0%\" stop-color=\"#0E9384\"/>\n          <stop offset=\"60%\" stop-color=\"#C2710C\"/>\n          <stop offset=\"100%\" stop-color=\"#D92D5C\"/>\n        </linearGradient>\n      </defs>\n      <rect x=\"20\" y=\"40\" width=\"660\" height=\"30\" rx=\"6\" fill=\"url(#cxgrad)\" opacity=\"0.15\"/>\n      <g text-anchor=\"middle\" font-size=\"11\">\n        <rect x=\"22\" y=\"42\" width=\"92\" height=\"26\" rx=\"5\" fill=\"#0E9384\"/>\n        <text x=\"68\" y=\"59\" fill=\"white\" font-weight=\"700\">O(1)</text>\n        <rect x=\"118\" y=\"42\" width=\"92\" height=\"26\" rx=\"5\" fill=\"#18937A\"/>\n        <text x=\"164\" y=\"59\" fill=\"white\" font-weight=\"700\">O(log n)</text>\n        <rect x=\"214\" y=\"42\" width=\"92\" height=\"26\" rx=\"5\" fill=\"#4F46E5\"/>\n        <text x=\"260\" y=\"59\" fill=\"white\" font-weight=\"700\">O(n)</text>\n        <rect x=\"310\" y=\"42\" width=\"92\" height=\"26\" rx=\"5\" fill=\"#7C3AED\"/>\n        <text x=\"356\" y=\"59\" fill=\"white\" font-weight=\"700\">O(n log n)</text>\n        <rect x=\"406\" y=\"42\" width=\"92\" height=\"26\" rx=\"5\" fill=\"#C2710C\"/>\n        <text x=\"452\" y=\"59\" fill=\"white\" font-weight=\"700\">O(n\u00b2)</text>\n        <rect x=\"502\" y=\"42\" width=\"92\" height=\"26\" rx=\"5\" fill=\"#D92D5C\"/>\n        <text x=\"548\" y=\"59\" fill=\"white\" font-weight=\"700\">O(2\u207f)</text>\n        <rect x=\"598\" y=\"42\" width=\"80\" height=\"26\" rx=\"5\" fill=\"#8B1C1C\"/>\n        <text x=\"638\" y=\"59\" fill=\"white\" font-weight=\"700\">O(n!)</text>\n      </g>\n      <g font-size=\"9\" fill=\"#5C6175\" text-anchor=\"middle\">\n        <text x=\"68\"  y=\"90\">dict/set lookup</text>\n        <text x=\"68\"  y=\"103\">list[i], len()</text>\n        <text x=\"164\" y=\"90\">binary search</text>\n        <text x=\"164\" y=\"103\">balanced BST</text>\n        <text x=\"260\" y=\"90\">one loop</text>\n        <text x=\"260\" y=\"103\">linear scan</text>\n        <text x=\"356\" y=\"90\">merge sort</text>\n        <text x=\"356\" y=\"103\">sorted()</text>\n        <text x=\"452\" y=\"90\">nested loops</text>\n        <text x=\"452\" y=\"103\">avoid for large n</text>\n        <text x=\"548\" y=\"90\">brute force</text>\n        <text x=\"548\" y=\"103\">subsets</text>\n        <text x=\"638\" y=\"90\">permutations</text>\n        <text x=\"638\" y=\"103\">avoid always</text>\n      </g>\n      <text x=\"20\"  y=\"135\" font-size=\"10\" fill=\"#0E9384\" font-weight=\"700\">\u2190 FAST</text>\n      <text x=\"625\" y=\"135\" font-size=\"10\" fill=\"#D92D5C\" font-weight=\"700\">SLOW \u2192</text>\n      <line x1=\"55\" y1=\"132\" x2=\"600\" y2=\"132\" stroke=\"#E7E8F0\" stroke-width=\"1\"/>\n    </svg>\n  </figure>\n\n  <!-- \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 2. RULES \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 -->\n  <h2 id=\"cx-rules\"><span class=\"num\">02</span>Big O Rules \u2014 apply mechanically</h2>\n\n  <table class=\"tbl\">\n    <tr><th>Rule</th><th>What it means</th><th>Example</th></tr>\n    <tr><td><strong>Drop constants</strong></td><td>Constants don't matter at scale</td><td>O(2n) \u2192 O(n)</td></tr>\n    <tr><td><strong>Drop lower terms</strong></td><td>Bigger term dominates</td><td>O(n\u00b2 + n) \u2192 O(n\u00b2)</td></tr>\n    <tr><td><strong>Multiple inputs = multiple vars</strong></td><td>Different arrays need different letters</td><td>O(n + m), not O(n)</td></tr>\n    <tr><td><strong>Hidden inner work counts</strong></td><td>Body cost multiplies the loop</td><td>loop with list scan \u2192 O(n\u00b2)</td></tr>\n    <tr><td><strong>in list = O(n)</strong></td><td>Full scan from index 0 every time</td><td>replace with set</td></tr>\n    <tr><td><strong>in set/dict = O(1)</strong></td><td>Hash lookup</td><td>most common interview fix</td></tr>\n  </table>\n\n  <div class=\"fx\"><span class=\"c\"># Rule 1 \u2014 Drop constants</span>\n<span class=\"k\">def</span> <span class=\"o\">example</span>(nums):\n    <span class=\"k\">for</span> n <span class=\"k\">in</span> nums: print(n)       <span class=\"c\"># O(n)</span>\n    <span class=\"k\">for</span> n <span class=\"k\">in</span> nums: print(n * <span class=\"y\">2</span>)   <span class=\"c\"># O(n)</span>\n<span class=\"c\"># O(2n) \u2192 drop constant \u2192 O(n)</span>\n\n<span class=\"c\"># Rule 2 \u2014 Multiple inputs</span>\n<span class=\"k\">def</span> <span class=\"o\">combine</span>(a, b):\n    <span class=\"k\">for</span> x <span class=\"k\">in</span> a: print(x)    <span class=\"c\"># n iterations</span>\n    <span class=\"k\">for</span> y <span class=\"k\">in</span> b: print(y)    <span class=\"c\"># m iterations</span>\n<span class=\"c\"># NOT O(n). It's O(n + m). a and b are different.</span>\n\n<span class=\"c\"># Rule 3 \u2014 Hidden inner cost (the most common mistake)</span>\n<span class=\"k\">def</span> <span class=\"o\">find_dup_slow</span>(nums):\n    seen = []\n    <span class=\"k\">for</span> num <span class=\"k\">in</span> nums:        <span class=\"c\"># O(n)</span>\n        <span class=\"k\">if</span> num <span class=\"k\">in</span> seen:      <span class=\"c\"># O(n) \u2014 list scans from 0 every time!</span>\n            <span class=\"k\">return</span> num\n        seen.append(num)\n<span class=\"c\"># Total: O(n\u00b2) \u2014 not O(n) despite \"one loop\"</span>\n\n<span class=\"k\">def</span> <span class=\"o\">find_dup_fast</span>(nums):\n    seen = set()\n    <span class=\"k\">for</span> num <span class=\"k\">in</span> nums:        <span class=\"c\"># O(n)</span>\n        <span class=\"k\">if</span> num <span class=\"k\">in</span> seen:      <span class=\"c\"># O(1) \u2014 hash lookup</span>\n            <span class=\"k\">return</span> num\n        seen.add(num)\n<span class=\"c\"># Total: O(n) \u2014 the fix is always: list \u2192 set</span></div>\n\n  <div class=\"callout trap\">\n    <span class=\"label\">The #1 hidden cost trap \u2014 what's inside the loop?</span>\n    <p>One loop \u2260 O(n). What matters is total work across all iterations. If the loop body calls <code>.sort()</code> (O(n log n)), searches a list (O(n)), or recurses (check depth), multiply. Always check the body, not just the loop count.</p>\n  </div>\n\n  <!-- \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 3. SPACE \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 -->\n  <h2 id=\"cx-space\"><span class=\"num\">03</span>Space Complexity</h2>\n\n  <div class=\"callout def\">\n    <span class=\"label\">Definition \u2014 Space Complexity</span>\n    <p>The extra memory your algorithm uses beyond the input itself. Key question: am I creating a new data structure that grows with input size? If yes \u2014 at minimum O(n). Swapping variables and in-place pointer manipulation stay O(1).</p>\n  </div>\n\n  <table class=\"tbl\">\n    <tr><th>Pattern</th><th>Space</th><th>Why</th></tr>\n    <tr><td>Swap / in-place pointer</td><td>O(1)</td><td>No new structure created</td></tr>\n    <tr><td>New list / set / dict</td><td>O(n)</td><td>Grows proportionally with input</td></tr>\n    <tr><td>Recursion \u2014 linear</td><td>O(n)</td><td>Call stack depth = n</td></tr>\n    <tr><td>Recursion \u2014 binary search</td><td>O(log n)</td><td>Stack depth halves each call</td></tr>\n    <tr><td>2D DP table</td><td>O(n\u00b7m)</td><td>One cell per subproblem</td></tr>\n  </table>\n\n  <div class=\"fx\"><span class=\"c\"># In-place \u2014 O(1) space</span>\n<span class=\"k\">def</span> <span class=\"o\">reverse_inplace</span>(nums):\n    left, right = <span class=\"y\">0</span>, len(nums) - <span class=\"y\">1</span>\n    <span class=\"k\">while</span> left < right:\n        nums[left], nums[right] = nums[right], nums[left]\n        left += <span class=\"y\">1</span>; right -= <span class=\"y\">1</span>\n    <span class=\"c\"># No new list. Just pointer swaps. Space: O(1)</span>\n\n<span class=\"c\"># New structure \u2014 O(n) space</span>\n<span class=\"k\">def</span> <span class=\"o\">reverse_new</span>(nums):\n    <span class=\"k\">return</span> list(reversed(nums))   <span class=\"c\"># new list grows with input. Space: O(n)</span>\n\n<span class=\"c\"># O(n+m) example \u2014 two inputs, two structures</span>\n<span class=\"k\">def</span> <span class=\"o\">has_common_fast</span>(a, b):\n    b_set = set(b)       <span class=\"c\"># O(m) space</span>\n    <span class=\"k\">for</span> x <span class=\"k\">in</span> a:          <span class=\"c\"># O(n) time</span>\n        <span class=\"k\">if</span> x <span class=\"k\">in</span> b_set:   <span class=\"c\"># O(1)</span>\n            <span class=\"k\">return True</span>\n    <span class=\"k\">return False</span>\n<span class=\"c\"># Time: O(n + m). Space: O(m) for the set.</span></div>\n\n  <!-- \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 4. AMORTIZED \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 -->\n  <h2 id=\"cx-amortized\"><span class=\"num\">04</span>Amortized Complexity</h2>\n\n  <div class=\"callout def\">\n    <span class=\"label\">Definition \u2014 Amortized Complexity</span>\n    <p>The average cost per operation over a <em>sequence</em> of operations \u2014 not the worst single case. A single operation might occasionally be expensive (e.g. resizing a list), but if that expensive case is rare enough, the average is still cheap.</p>\n  </div>\n\n  <div class=\"callout intu\">\n    <span class=\"label\">Why list.append() is O(1) amortized</span>\n    <p>Python lists use a dynamic array. When full, Python doubles the capacity and copies everything \u2014 O(n). But doublings happen at capacities 1, 2, 4, 8, 16... Total copy work across n appends = 1+2+4+...+n \u2248 2n = O(n). Spread over n appends: O(n)/n = <strong>O(1) per append</strong>.</p>\n  </div>\n\n  <div class=\"fx\"><span class=\"c\"># Resizes at: 1, 2, 4, 8, 16, 32... (doubling)</span>\n<span class=\"c\"># Total copy work across n appends: 1+2+4+...+n = ~2n = O(n)</span>\n<span class=\"c\"># Spread over n appends: O(n)/n = O(1) amortized</span>\nnums = []\n<span class=\"k\">for</span> i <span class=\"k\">in</span> range(<span class=\"y\">1_000_000</span>):\n    nums.append(i)    <span class=\"c\"># O(1) amortized \u2014 not O(n) each time</span>\n\n<span class=\"c\"># dict worst case \u2014 hash collisions</span>\n<span class=\"c\"># Average: O(1). Worst: O(n) if all keys hash to same bucket.</span>\n<span class=\"c\"># Only happens with a broken __hash__ on custom objects.</span>\n<span class=\"c\"># Always say O(1) in interviews unless discussing internals.</span>\nd = {}\nd[<span class=\"g\">\"key\"</span>] = <span class=\"y\">42</span>     <span class=\"c\"># O(1) average</span>\n_ = d[<span class=\"g\">\"key\"</span>]      <span class=\"c\"># O(1) average</span></div>\n\n  <!-- \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 5. BUILTINS \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 -->\n  <h2 id=\"cx-builtins\"><span class=\"num\">05</span>Python Built-ins \u2014 actual costs</h2>\n\n  <table class=\"tbl\">\n    <tr><th>Operation</th><th>Time</th><th>Why</th></tr>\n    <tr><td><code>list[i]</code></td><td>O(1)</td><td>Direct index access</td></tr>\n    <tr><td><code>list.append(x)</code></td><td>O(1) amortized</td><td>Occasional O(n) resize, rare</td></tr>\n    <tr><td><code>list.insert(0, x)</code></td><td>O(n)</td><td>Shifts every element right</td></tr>\n    <tr><td><code>list.pop()</code></td><td>O(1)</td><td>Remove from end</td></tr>\n    <tr><td><code>list.pop(0)</code></td><td>O(n)</td><td>Shifts every element left</td></tr>\n    <tr><td><code>x in list</code></td><td>O(n)</td><td>Full scan from index 0</td></tr>\n    <tr><td><code>x in set</code></td><td>O(1)</td><td>Hash lookup</td></tr>\n    <tr><td><code>dict[key]</code></td><td>O(1) avg / O(n) worst</td><td>Worst = all keys collide</td></tr>\n    <tr><td><code>sorted() / .sort()</code></td><td>O(n log n)</td><td>Timsort</td></tr>\n    <tr><td><code>len(x)</code></td><td>O(1)</td><td>Stored as metadata in the object</td></tr>\n    <tr><td><code>list slicing [i:j]</code></td><td>O(k)</td><td>k = j-i, copies k elements</td></tr>\n    <tr><td><code>str + str</code></td><td>O(n+m)</td><td>Creates new string, copies both</td></tr>\n    <tr><td><code>\"\".join(lst)</code></td><td>O(n)</td><td>One allocation, one copy</td></tr>\n    <tr><td><code>collections.deque.appendleft()</code></td><td>O(1)</td><td>Doubly-linked structure</td></tr>\n    <tr><td><code>heapq.heappush()</code></td><td>O(log n)</td><td>Sifts up in heap</td></tr>\n    <tr><td><code>heapq.heappop()</code></td><td>O(log n)</td><td>Sifts down in heap</td></tr>\n  </table>\n\n  <div class=\"callout trap\">\n    <span class=\"label\">The string concatenation trap in loops</span>\n    <p>Building a string with <code>result += char</code> inside a loop is O(n\u00b2) because each <code>+</code> creates a new string and copies everything. Always collect parts in a list and join at the end: <code>\"\".join(parts)</code> = O(n).</p>\n    <div class=\"fx\"><span class=\"c\"># SLOW \u2014 O(n\u00b2)</span>\nresult = <span class=\"g\">\"\"</span>\n<span class=\"k\">for</span> char <span class=\"k\">in</span> chars:\n    result += char   <span class=\"c\"># creates new string every time</span>\n\n<span class=\"c\"># FAST \u2014 O(n)</span>\nresult = <span class=\"g\">\"\"</span>.join(chars)   <span class=\"c\"># one allocation</span></div>\n  </div>\n\n  <!-- \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 6. FRAMEWORK \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 -->\n  <h2 id=\"cx-framework\"><span class=\"num\">06</span>Interview Analysis Framework \u2014 3 steps</h2>\n\n  <div class=\"callout intu\">\n    <span class=\"label\">Apply this on every problem, every time</span>\n    <p>Before writing code or right after, walk through these three steps out loud. Interviewers are listening for this analysis. Not doing it = missing points even if the code is correct.</p>\n  </div>\n\n  <div class=\"fx\"><span class=\"c\"># STEP 1 \u2014 Count the loops</span>\n<span class=\"c\"># Each nesting level multiplies:</span>\n<span class=\"c\"># 1 loop = O(n), 2 nested = O(n\u00b2), 3 nested = O(n\u00b3)</span>\n\n<span class=\"c\"># STEP 2 \u2014 Check the loop body</span>\n<span class=\"c\"># Hidden O(n) ops inside a loop multiply the outer loop</span>\n<span class=\"c\"># Common hidden costs: list scan, .sort(), recursion</span>\n\n<span class=\"c\"># STEP 3 \u2014 Apply rules + state both time AND space</span>\n<span class=\"c\"># Drop constants. Drop lower terms.</span>\n<span class=\"c\"># Separate variables for separate inputs (O(n + m) not O(n))</span>\n\n<span class=\"c\"># \u2500\u2500 Worked example \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span class=\"c\"># SLOW \u2014 O(n * m) time, O(1) space</span>\n<span class=\"k\">def</span> <span class=\"o\">has_common</span>(a, b):\n    <span class=\"k\">for</span> x <span class=\"k\">in</span> a:           <span class=\"c\"># O(n)</span>\n        <span class=\"k\">if</span> x <span class=\"k\">in</span> b:         <span class=\"c\"># O(m) \u2014 b is a list, full scan</span>\n            <span class=\"k\">return True</span>\n    <span class=\"k\">return False</span>\n\n<span class=\"c\"># FAST \u2014 O(n + m) time, O(m) space</span>\n<span class=\"k\">def</span> <span class=\"o\">has_common_fast</span>(a, b):\n    b_set = set(b)          <span class=\"c\"># O(m) time + space to build</span>\n    <span class=\"k\">for</span> x <span class=\"k\">in</span> a:             <span class=\"c\"># O(n)</span>\n        <span class=\"k\">if</span> x <span class=\"k\">in</span> b_set:     <span class=\"c\"># O(1) \u2014 hash lookup</span>\n            <span class=\"k\">return True</span>\n    <span class=\"k\">return False</span>\n<span class=\"c\"># Time: O(n + m). Space: O(m).</span>\n<span class=\"c\"># Tradeoff: we spent O(m) space to save O(n\u00b7m) \u2192 O(n+m) time.</span></div>\n\n  <h2 id=\"cx-qa\"><span class=\"num\">07</span>Interview Q&amp;A</h2>\n  <div class=\"qa-head\"><h3>Answer before revealing</h3><button class=\"reveal-all\" id=\"revealAll\">Reveal all</button></div>\n\n  <details class=\"qa\"><summary><span class=\"qmark\">Q</span>What is amortized O(1) and when does list.append() apply?</summary><div class=\"qa-body\">Amortized O(1) means the average cost per operation over a sequence is O(1), even if individual operations are occasionally expensive. list.append() is amortized O(1) because Python uses a dynamic array that doubles capacity when full \u2014 copying all elements costs O(n), but doublings happen so rarely (at sizes 1,2,4,8,...) that the total copy work across n appends is O(n), making the average O(1) per append.</div></details>\n\n  <details class=\"qa\"><summary><span class=\"qmark\">Q</span>Why is \"x in list\" O(n) but \"x in set\" O(1)?</summary><div class=\"qa-body\">A Python list stores elements contiguously in memory with no additional structure. Checking membership requires scanning from index 0 until the element is found or the list is exhausted \u2014 O(n). A set uses a hash table: it computes hash(x), finds the bucket directly, and checks \u2014 O(1) average. This is why replacing a list with a set is the most common O(n\u00b2) \u2192 O(n) fix: the outer loop is still O(n), but the inner membership check drops from O(n) to O(1).</div></details>\n\n  <details class=\"qa\"><summary><span class=\"qmark\">Q</span>What's the space complexity of a recursive function?</summary><div class=\"qa-body\">Each recursive call adds a frame to the call stack. Space complexity = O(maximum recursion depth). For linear recursion (processing a linked list, DFS through an unsorted array) = O(n). For binary search (halving the problem each call) = O(log n). For a balanced binary tree DFS = O(h) = O(log n) average, O(n) worst case if the tree is skewed. The stack is freed as calls return \u2014 it's not all held simultaneously in aggregate, but the maximum live frames at one moment is the depth.</div></details>\n\n  <details class=\"qa\"><summary><span class=\"qmark\">Q</span>How do you handle multiple inputs in Big O analysis?</summary><div class=\"qa-body\">Each independent input gets its own variable. If a function takes array A of length n and array B of length m, and loops through both, the complexity is O(n + m) \u2014 not O(n). You cannot assume n \u2248 m unless explicitly stated. If nested (looping A inside a loop over B), it's O(n * m), not O(n\u00b2). This matters whenever two separate collections are involved \u2014 graphs (V vertices, E edges \u2192 O(V + E)), two strings, two lists, etc.</div></details>\n\n  <details class=\"qa\"><summary><span class=\"qmark\">Q</span>What is the time complexity of Python's sorted() and .sort()?</summary><div class=\"qa-body\">Both use Timsort \u2014 O(n log n) time, O(n) auxiliary space. Timsort is a hybrid of merge sort and insertion sort, optimised for real-world data that often has partially sorted runs. It's stable (preserves relative order of equal elements). The in-place .sort() uses O(log n) space (recursion stack) rather than O(n). If you call .sort() inside a loop, the total becomes O(n\u00b2 log n) \u2014 a common hidden cost trap.</div></details>\n</main>\n",
  "dsa_problems": "<main>\n<h1>DSA Problem Tracker</h1>\n<style>\n.prob-controls{display:flex;gap:10px;flex-wrap:wrap;align-items:center;margin-bottom:18px}\n.prob-controls input{flex:1;min-width:160px;padding:7px 12px;border:1.5px solid var(--border);border-radius:8px;background:var(--bg-card);color:var(--text);font-size:13px}\n.prob-controls select{padding:7px 10px;border:1.5px solid var(--border);border-radius:8px;background:var(--bg-card);color:var(--text);font-size:13px}\n.prob-stats{display:flex;gap:12px;flex-wrap:wrap;margin-bottom:18px}\n.stat-chip{background:var(--bg-card);border:1.5px solid var(--border);border-radius:20px;padding:5px 14px;font-size:12px;font-weight:600}\n.stat-chip span{color:#0E9384}\n.phase-header{background:var(--bg-card);border:1.5px solid var(--border);border-radius:10px;padding:12px 16px;margin:18px 0 8px;cursor:pointer;display:flex;justify-content:space-between;align-items:center;user-select:none}\n.phase-header:hover{border-color:#4F46E5}\n.phase-title{font-weight:700;font-size:14px}\n.phase-meta{font-size:12px;color:var(--text-muted);display:flex;gap:10px;align-items:center}\n.phase-progress{height:6px;background:var(--border);border-radius:3px;margin:6px 0 0;width:100%}\n.phase-progress-fill{height:100%;border-radius:3px;background:#0E9384;transition:width .3s}\n.phase-body{display:none;padding:0 2px}\n.phase-body.open{display:block}\n.prob-row{display:grid;grid-template-columns:32px 1fr 72px 80px 40px;gap:8px;align-items:start;padding:10px 8px;border-bottom:1px solid var(--border);transition:background .15s}\n.prob-row:hover{background:var(--bg-card)}\n.prob-row:last-child{border-bottom:none}\n.prob-num{color:var(--text-muted);font-size:12px;font-weight:600;padding-top:2px}\n.prob-main{}\n.prob-name{font-weight:600;font-size:13px;margin-bottom:3px}\n.prob-name a{color:var(--text);text-decoration:none}\n.prob-name a:hover{color:#4F46E5}\n.prob-hints{margin-top:4px}\n.hint-optimal{background:#E5F6F3;color:#0E9384;border-radius:5px;padding:3px 8px;font-size:11px;margin-bottom:3px;display:block}\n.hint-technique{background:#EEF0FF;color:#4F46E5;border-radius:5px;padding:3px 8px;font-size:11px;margin-bottom:3px;display:block;cursor:pointer}\n.hint-algo{background:#FEF5E7;color:#C2710C;border-radius:5px;padding:3px 8px;font-size:11px;cursor:pointer;display:block}\n.hint-algo-body{display:none;background:#FEF5E7;color:#7A4510;border-radius:0 0 5px 5px;padding:4px 8px;font-size:11px;line-height:1.5}\n.hint-algo-body.open{display:block}\n.diff-badge{padding:3px 10px;border-radius:20px;font-size:11px;font-weight:700;text-align:center;white-space:nowrap}\n.diff-easy{background:#E5F6F3;color:#0E9384}\n.diff-medium{background:#FEF5E7;color:#C2710C}\n.diff-hard{background:#FDEAEF;color:#D92D5C}\n.prob-check{display:flex;justify-content:center;padding-top:2px}\n.prob-check input[type=checkbox]{width:16px;height:16px;cursor:pointer;accent-color:#0E9384}\n.section-label{font-size:11px;font-weight:700;color:var(--text-muted);letter-spacing:.05em;text-transform:uppercase;padding:10px 8px 4px;border-bottom:1px solid var(--border)}\n.hidden-prob{display:none}\n.no-results{text-align:center;color:var(--text-muted);padding:40px;font-size:14px}\n</style>\n\n<div class=\"prob-controls\">\n  <input type=\"text\" id=\"probSearch\" placeholder=\"Search problems...\" oninput=\"filterProbs()\">\n  <select id=\"diffFilter\" onchange=\"filterProbs()\">\n    <option value=\"\">All difficulties</option>\n    <option value=\"Easy\">Easy</option>\n    <option value=\"Medium\">Medium</option>\n    <option value=\"Hard\">Hard</option>\n  </select>\n  <select id=\"phaseFilter\" onchange=\"filterProbs()\">\n    <option value=\"\">All phases</option>\n    <option value=\"0\">01 \u2014 Complexity</option>\n    <option value=\"1\">02 \u2014 Arrays & Strings</option>\n    <option value=\"2\">03 \u2014 Hashing</option>\n    <option value=\"3\">04 \u2014 Linked Lists</option>\n    <option value=\"4\">05 \u2014 Stacks & Queues</option>\n    <option value=\"5\">06 \u2014 Binary Search</option>\n    <option value=\"6\">07 \u2014 Trees</option>\n    <option value=\"7\">08 \u2014 Heaps</option>\n    <option value=\"8\">09 \u2014 Graphs</option>\n    <option value=\"9\">10 \u2014 Backtracking</option>\n    <option value=\"10\">11 \u2014 DP</option>\n    <option value=\"11\">12 \u2014 Tries</option>\n    <option value=\"12\">13 \u2014 Bit Manipulation</option>\n    <option value=\"13\">14 \u2014 Advanced DS</option>\n    <option value=\"14\">15 \u2014 Sorting</option>\n    <option value=\"15\">16 \u2014 Intervals & Greedy</option>\n    <option value=\"16\">17 \u2014 Math</option>\n  </select>\n  <select id=\"statusFilter\" onchange=\"filterProbs()\">\n    <option value=\"\">All statuses</option>\n    <option value=\"solved\">Solved</option>\n    <option value=\"unsolved\">Unsolved</option>\n  </select>\n  <button onclick=\"resetAll()\" style=\"padding:7px 14px;border-radius:8px;border:1.5px solid var(--border);background:var(--bg-card);color:var(--text);cursor:pointer;font-size:13px\">Reset filters</button>\n</div>\n\n<div class=\"prob-stats\" id=\"probStats\"></div>\n<div id=\"probContainer\"></div>\n\n<script>\nconst PHASES = [\n  {\n    title:\"01 \u2014 Complexity & Python Internals\", level:\"Foundation\", count:1,\n    sections:[\n      {label:\"Big O Practice\",problems:[\n        {name:\"Big O Notation reasoning drills\",url:\"\",diff:\"Easy\",opt:\"Conceptual \u2014 analyze your own code\",hint:\"This phase is conceptual. Analyze your own code's complexity until it's automatic.\",algo:\"Practice: write a function, then determine its time and space complexity. Repeat until it's instant.\"}\n      ]}\n    ]\n  },\n  {\n    title:\"02 \u2014 Arrays & Strings\", level:\"Core DSA\", count:28,\n    sections:[\n      {label:\"Array Basics\",problems:[\n        {name:\"Remove Duplicates from Sorted Array\",url:\"https://leetcode.com/problems/remove-duplicates-from-sorted-array/\",diff:\"Easy\",opt:\"O(n) time, O(1) space\",hint:\"Sorted array \u2192 duplicates adjacent. Two pointers: slow marks next unique slot, fast scans ahead.\",algo:\"1. slow=0. 2. Walk fast from 1. 3. When nums[fast]!=nums[slow]: slow++, nums[slow]=nums[fast]. 4. Return slow+1.\"},\n        {name:\"Rotate Array\",url:\"https://leetcode.com/problems/rotate-array/\",diff:\"Medium\",opt:\"O(n) time, O(1) space\",hint:\"Three reversals: reverse all, reverse first k, reverse remaining n-k.\",algo:\"1. k = k%n. 2. Reverse entire array. 3. Reverse first k. 4. Reverse last n-k.\"},\n        {name:\"Merge Sorted Array\",url:\"https://leetcode.com/problems/merge-sorted-array/\",diff:\"Easy\",opt:\"O(n+m) time, O(1) space\",hint:\"Extra space at end of nums1 \u2014 fill from the back. Compare largest remaining from both.\",algo:\"1. p1=m-1, p2=n-1, write=m+n-1. 2. Compare nums1[p1] vs nums2[p2], place larger at write. 3. Decrement source pointer + write. 4. Copy remaining nums2 if p1 exhausted.\"}\n      ]},\n      {label:\"Two Pointers\",problems:[\n        {name:\"Valid Palindrome\",url:\"https://leetcode.com/problems/valid-palindrome/\",diff:\"Easy\",opt:\"O(n) time, O(1) space\",hint:\"Two pointers from ends, skip non-alphanumeric, compare lowercase.\",algo:\"1. left=0, right=n-1. 2. Skip non-alnum on both sides. 3. Compare lowercase chars. 4. Move inward. Return true if loop completes.\"},\n        {name:\"Two Sum II \u2014 Input Array Is Sorted\",url:\"https://leetcode.com/problems/two-sum-ii-input-array-is-sorted/\",diff:\"Medium\",opt:\"O(n) time, O(1) space\",hint:\"Sorted \u2192 two pointers from ends. Sum too small \u2192 move left right. Too big \u2192 move right left.\",algo:\"1. left=0, right=n-1. 2. sum=numbers[left]+numbers[right]. 3. ==target \u2192 return [left+1,right+1]. 4. <target \u2192 left++. 5. >target \u2192 right--.\"},\n        {name:\"3Sum\",url:\"https://leetcode.com/problems/3sum/\",diff:\"Medium\",opt:\"O(n\u00b2) time, O(1) extra space\",hint:\"Sort first. Fix one element, two-pointer on rest. Skip duplicates at each level.\",algo:\"1. Sort. 2. For i, skip if nums[i]==nums[i-1]. 3. left=i+1, right=n-1. 4. sum==0 \u2192 record, move both, skip dups. 5. <0 \u2192 left++. >0 \u2192 right--.\"},\n        {name:\"Container With Most Water\",url:\"https://leetcode.com/problems/container-with-most-water/\",diff:\"Medium\",opt:\"O(n) time, O(1) space\",hint:\"Two pointers from ends. Area = min(height[l],height[r])*(r-l). Always move the shorter wall inward.\",algo:\"1. left=0, right=n-1. 2. Compute area, track max. 3. Move pointer at shorter wall. 4. Stop when left meets right.\"},\n        {name:\"Trapping Rain Water\",url:\"https://leetcode.com/problems/trapping-rain-water/\",diff:\"Hard\",opt:\"O(n) time, O(1) space\",hint:\"Water at index = min(leftMax, rightMax) - height. Two pointers tracking both maxes in one pass.\",algo:\"1. left=0,right=n-1,lMax=0,rMax=0,res=0. 2. If h[left]<h[right]: update lMax, add lMax-h[left] to res, left++. 3. Else: update rMax, add rMax-h[right], right--.\"}\n      ]},\n      {label:\"Sliding Window\",problems:[\n        {name:\"Best Time to Buy and Sell Stock\",url:\"https://leetcode.com/problems/best-time-to-buy-and-sell-stock/\",diff:\"Easy\",opt:\"O(n) time, O(1) space\",hint:\"Track min price seen so far. At each day: profit = price - minPrice. Track max profit.\",algo:\"1. minPrice=\u221e, maxProfit=0. 2. For each price: update minPrice. 3. profit=price-minPrice, update maxProfit. 4. Return maxProfit.\"},\n        {name:\"Maximum Average Subarray I\",url:\"https://leetcode.com/problems/maximum-average-subarray-i/\",diff:\"Easy\",opt:\"O(n) time, O(1) space\",hint:\"Fixed window k. Compute first k sum, slide: subtract leaving element, add entering.\",algo:\"1. Sum first k elements \u2192 currentSum=maxSum. 2. Slide: currentSum += nums[i]-nums[i-k]. 3. maxSum=max(maxSum,currentSum). 4. Return maxSum/k.\"},\n        {name:\"Longest Substring Without Repeating Characters\",url:\"https://leetcode.com/problems/longest-substring-without-repeating-characters/\",diff:\"Medium\",opt:\"O(n) time, O(min(n,charset)) space\",hint:\"Variable sliding window + set tracking chars in window. Expand right, shrink left on repeat.\",algo:\"1. set, left=0. 2. For right: while s[right] in set, remove s[left], left++. 3. Add s[right]. 4. maxLen=max(maxLen, right-left+1).\"},\n        {name:\"Longest Repeating Character Replacement\",url:\"https://leetcode.com/problems/longest-repeating-character-replacement/\",diff:\"Medium\",opt:\"O(n) time, O(26) space\",hint:\"Sliding window. Valid if (windowSize - maxFreq) <= k. Shrink from left when invalid.\",algo:\"1. freq dict, left=0, maxFreq=0. 2. For right: freq[s[right]]++, update maxFreq. 3. If window-maxFreq>k: freq[s[left]]--, left++. 4. Track maxLen.\"},\n        {name:\"Minimum Window Substring\",url:\"https://leetcode.com/problems/minimum-window-substring/\",diff:\"Hard\",opt:\"O(n+m) time, O(charset) space\",hint:\"Variable window. Expand right until valid (covers t). Shrink left while still valid. Track minimum.\",algo:\"1. Freq map of t. 2. left=0, counter=distinct chars in t. 3. Expand right: decrement needed. When counter==0 (valid): shrink left as much as possible, record min window. 4. Continue.\"},\n        {name:\"Sliding Window Maximum\",url:\"https://leetcode.com/problems/sliding-window-maximum/\",diff:\"Hard\",opt:\"O(n) time, O(k) space\",hint:\"Monotonic decreasing deque of indices. Remove back if smaller than current. Remove front if outside window.\",algo:\"1. deque of indices. 2. For each i: remove back if nums[i]>nums[deque.back()]. 3. Add i to back. 4. Remove front if outside window (i-k). 5. Once i>=k-1, front is current max.\"}\n      ]},\n      {label:\"Prefix Sums\",problems:[\n        {name:\"Range Sum Query \u2014 Immutable\",url:\"https://leetcode.com/problems/range-sum-query-immutable/\",diff:\"Easy\",opt:\"O(n) preprocess, O(1) query\",hint:\"Prefix array: prefix[i] = sum(0..i-1). Range sum(i,j) = prefix[j+1]-prefix[i].\",algo:\"1. Build prefix[0]=0, prefix[i]=prefix[i-1]+nums[i-1]. 2. sumRange(i,j)=prefix[j+1]-prefix[i].\"},\n        {name:\"Find Pivot Index\",url:\"https://leetcode.com/problems/find-pivot-index/\",diff:\"Easy\",opt:\"O(n) time, O(1) space\",hint:\"Total sum first. leftSum running. rightSum = total - leftSum - nums[i]. Compare.\",algo:\"1. totalSum=sum(nums). 2. leftSum=0. 3. For each i: rightSum=totalSum-leftSum-nums[i]. 4. If equal \u2192 return i. 5. leftSum+=nums[i]. Return -1.\"},\n        {name:\"Subarray Sum Equals K\",url:\"https://leetcode.com/problems/subarray-sum-equals-k/\",diff:\"Medium\",opt:\"O(n) time, O(n) space\",hint:\"Running prefixSum + hashmap counting occurrences. At index i: if (prefixSum-k) seen before, those many subarrays end here.\",algo:\"1. dict={0:1}, prefixSum=0, ans=0. 2. For each num: prefixSum+=num. 3. ans+=dict.get(prefixSum-k,0). 4. dict[prefixSum]++.\"},\n        {name:\"Product of Array Except Self\",url:\"https://leetcode.com/problems/product-of-array-except-self/\",diff:\"Medium\",opt:\"O(n) time, O(1) extra space\",hint:\"Two passes. Left\u2192right: result[i]=product of all left of i. Right\u2192left: multiply in right products using running variable.\",algo:\"1. Left pass: result[0]=1, result[i]=result[i-1]*nums[i-1]. 2. rightProduct=1. 3. Right pass: result[i]*=rightProduct, rightProduct*=nums[i].\"}\n      ]},\n      {label:\"Kadane's Algorithm\",problems:[\n        {name:\"Maximum Subarray\",url:\"https://leetcode.com/problems/maximum-subarray/\",diff:\"Medium\",opt:\"O(n) time, O(1) space\",hint:\"currentSum = max(nums[i], currentSum+nums[i]). Extend or restart. Track max.\",algo:\"1. cur=nums[0], maxSum=nums[0]. 2. For nums[1:]: cur=max(nums[i],cur+nums[i]). 3. maxSum=max(maxSum,cur). 4. Return maxSum.\"},\n        {name:\"Maximum Product Subarray\",url:\"https://leetcode.com/problems/maximum-product-subarray/\",diff:\"Medium\",opt:\"O(n) time, O(1) space\",hint:\"Track both max AND min (negative*negative=positive). On negative number, swap max and min.\",algo:\"1. curMax=curMin=res=nums[0]. 2. For nums[1:]: if neg, swap curMax,curMin. 3. curMax=max(n,curMax*n). 4. curMin=min(n,curMin*n). 5. res=max(res,curMax).\"}\n      ]},\n      {label:\"String Manipulation\",problems:[\n        {name:\"Reverse String\",url:\"https://leetcode.com/problems/reverse-string/\",diff:\"Easy\",opt:\"O(n) time, O(1) space\",hint:\"Two pointers from both ends, swap and move inward.\",algo:\"1. left=0,right=n-1. 2. While left<right: swap s[left],s[right]. 3. left++,right--.\"},\n        {name:\"Valid Anagram\",url:\"https://leetcode.com/problems/valid-anagram/\",diff:\"Easy\",opt:\"O(n) time, O(1) space\",hint:\"Frequency count: increment for s, decrement for t. All zeros = anagram.\",algo:\"1. If len(s)!=len(t) return false. 2. Freq dict for s. 3. For t: decrement; if goes negative \u2192 false. 4. Return true.\"},\n        {name:\"Longest Palindromic Substring\",url:\"https://leetcode.com/problems/longest-palindromic-substring/\",diff:\"Medium\",opt:\"O(n\u00b2) time, O(1) space\",hint:\"Expand around center. For each index: odd-length (single center) and even-length (between two chars).\",algo:\"1. For each i: expand odd (l=i-1,r=i+1) and even (l=i,r=i+1) while chars match. 2. Track start+length of longest found. 3. Return substring.\"},\n        {name:\"Group Anagrams\",url:\"https://leetcode.com/problems/group-anagrams/\",diff:\"Medium\",opt:\"O(n\u00b7k log k) time, O(nk) space\",hint:\"Anagrams share same sorted string. Use sorted(word) as dict key.\",algo:\"1. dict = defaultdict(list). 2. For each word: key=tuple(sorted(word)). 3. dict[key].append(word). 4. Return list(dict.values()).\"}\n      ]},\n      {label:\"Matrix / 2D Arrays\",problems:[\n        {name:\"Rotate Image\",url:\"https://leetcode.com/problems/rotate-image/\",diff:\"Medium\",opt:\"O(n\u00b2) time, O(1) space\",hint:\"Rotate 90\u00b0 clockwise = transpose + reverse each row.\",algo:\"1. Transpose: swap matrix[i][j] with matrix[j][i] for j>i. 2. Reverse each row.\"},\n        {name:\"Spiral Matrix\",url:\"https://leetcode.com/problems/spiral-matrix/\",diff:\"Medium\",opt:\"O(m\u00b7n) time, O(1) extra\",hint:\"Four boundaries: top,bottom,left,right. Traverse right\u2192down\u2192left\u2192up, shrink each boundary.\",algo:\"1. top=0,bottom=rows-1,left=0,right=cols-1. 2. Traverse right along top, top++. 3. Down along right, right--. 4. If top<=bottom: left along bottom, bottom--. 5. If left<=right: up along left, left++. Repeat.\"},\n        {name:\"Set Matrix Zeroes\",url:\"https://leetcode.com/problems/set-matrix-zeroes/\",diff:\"Medium\",opt:\"O(m\u00b7n) time, O(1) space\",hint:\"Use first row+col as markers. Two boolean flags for first row/col themselves.\",algo:\"1. Flags for first row/col. 2. If matrix[i][j]==0: set matrix[i][0]=0, matrix[0][j]=0. 3. Zero cells based on markers. 4. Zero first row/col per flags.\"},\n        {name:\"Search a 2D Matrix\",url:\"https://leetcode.com/problems/search-a-2d-matrix/\",diff:\"Medium\",opt:\"O(log(m\u00b7n)) time, O(1) space\",hint:\"Treat 2D matrix as flat sorted array. Binary search with index conversion mid\u2192row=mid//cols, col=mid%cols.\",algo:\"1. low=0,high=rows*cols-1. 2. mid=(low+high)//2. row=mid//cols, col=mid%cols. 3. Compare matrix[row][col] to target. Adjust low/high.\"}\n      ]}\n    ]\n  },\n  {\n    title:\"03 \u2014 Hashing\", level:\"Core DSA\", count:11,\n    sections:[\n      {label:\"Dict & Set Patterns\",problems:[\n        {name:\"Contains Duplicate\",url:\"https://leetcode.com/problems/contains-duplicate/\",diff:\"Easy\",opt:\"O(n) time, O(n) space\",hint:\"Add to set. If already in set \u2192 duplicate.\",algo:\"1. seen=set(). 2. For num: if in seen \u2192 True. 3. seen.add(num). 4. Return False.\"},\n        {name:\"Single Number\",url:\"https://leetcode.com/problems/single-number/\",diff:\"Easy\",opt:\"O(n) time, O(1) space\",hint:\"XOR all elements. a XOR a = 0. a XOR 0 = a. Pairs cancel, single survives.\",algo:\"1. res=0. 2. For num: res^=num. 3. Return res.\"},\n        {name:\"Majority Element\",url:\"https://leetcode.com/problems/majority-element/\",diff:\"Easy\",opt:\"O(n) time, O(1) space\",hint:\"Boyer-Moore voting. candidate + counter. If counter=0, pick current. Same \u2192 count++. Different \u2192 count--.\",algo:\"1. candidate=None, count=0. 2. For num: if count==0: candidate=num. 3. count += 1 if num==candidate else -1. 4. Return candidate.\"},\n        {name:\"Top K Frequent Elements\",url:\"https://leetcode.com/problems/top-k-frequent-elements/\",diff:\"Medium\",opt:\"O(n log k) time, O(n) space\",hint:\"Freq dict + min-heap of size k. Push (freq, elem). Pop if >k. Remaining = top k.\",algo:\"1. freq = Counter(nums). 2. heap=[]. 3. For (v,freq): heappush(heap,(freq,v)); if len>k: heappop. 4. Return [v for _,v in heap].\"},\n        {name:\"Two Sum\",url:\"https://leetcode.com/problems/two-sum/\",diff:\"Easy\",opt:\"O(n) time, O(n) space\",hint:\"Dict: value\u2192index. For each element: check if complement exists before adding.\",algo:\"1. seen={}. 2. For i,num: comp=target-num. 3. If comp in seen: return [seen[comp],i]. 4. seen[num]=i.\"},\n        {name:\"4Sum II\",url:\"https://leetcode.com/problems/4sum-ii/\",diff:\"Medium\",opt:\"O(n\u00b2) time, O(n\u00b2) space\",hint:\"Split into halves. Dict of all sums of pairs from A+B. For C+D: check if -(c+d) in dict.\",algo:\"1. Build dict counting all (a+b) for a in A, b in B. 2. ans=0. 3. For c in C, d in D: ans+=dict.get(-(c+d),0). 4. Return ans.\"}\n      ]},\n      {label:\"Group Anagrams\",problems:[\n        {name:\"Group Anagrams\",url:\"https://leetcode.com/problems/group-anagrams/\",diff:\"Medium\",opt:\"O(n\u00b7k log k) time, O(nk) space\",hint:\"Sorted word = anagram key. Group under that key.\",algo:\"1. d=defaultdict(list). 2. For word: key=''.join(sorted(word)). 3. d[key].append(word). 4. Return list(d.values()).\"},\n        {name:\"Isomorphic Strings\",url:\"https://leetcode.com/problems/isomorphic-strings/\",diff:\"Easy\",opt:\"O(n) time, O(1) space\",hint:\"Two dicts for bidirectional mapping. At each position verify both stay consistent.\",algo:\"1. mapST={}, mapTS={}. 2. For s[i],t[i]: if s[i] in mapST and mapST[s[i]]!=t[i]: False. If t[i] in mapTS and mapTS[t[i]]!=s[i]: False. 3. Set both mappings.\"}\n      ]},\n      {label:\"Subarray + Hashing\",problems:[\n        {name:\"Subarray Sum Equals K\",url:\"https://leetcode.com/problems/subarray-sum-equals-k/\",diff:\"Medium\",opt:\"O(n) time, O(n) space\",hint:\"Running prefixSum + dict counting occurrences. ans+=dict[prefixSum-k].\",algo:\"1. d={0:1}, ps=0, ans=0. 2. For num: ps+=num. 3. ans+=d.get(ps-k,0). 4. d[ps]=d.get(ps,0)+1.\"},\n        {name:\"Longest Consecutive Sequence\",url:\"https://leetcode.com/problems/longest-consecutive-sequence/\",diff:\"Medium\",opt:\"O(n) time, O(n) space\",hint:\"Set of all nums. Only start counting when (num-1) NOT in set. Count forward.\",algo:\"1. num_set=set(nums). 2. For num: if num-1 not in set: count from num. 3. While num+1 in set: num++, count++. 4. Track max.\"},\n        {name:\"Continuous Subarray Sum\",url:\"https://leetcode.com/problems/continuous-subarray-sum/\",diff:\"Medium\",opt:\"O(n) time, O(k) space\",hint:\"Running sum%k. If same remainder seen before at distance \u22652, subarray between is divisible by k.\",algo:\"1. d={0:-1}, ps=0. 2. For i,num: ps+=num; r=ps%k. 3. If r in d and i-d[r]>=2: True. 4. If r not in d: d[r]=i.\"}\n      ]}\n    ]\n  },\n  {\n    title:\"04 \u2014 Linked Lists\", level:\"Core DSA\", count:15,\n    sections:[\n      {label:\"Singly Linked List\",problems:[\n        {name:\"Design Linked List\",url:\"https://leetcode.com/problems/design-linked-list/\",diff:\"Medium\",opt:\"O(1) head ops, O(n) arbitrary\",hint:\"Node class + head pointer + size. Each op walks to target position.\",algo:\"1. Node(val,next). 2. get(i): walk i steps. 3. addAtHead: new node, new.next=head. 4. addAtIndex: walk to i-1, relink. 5. delete: walk to i-1, skip target.\"},\n        {name:\"Delete Node in a Linked List\",url:\"https://leetcode.com/problems/delete-node-in-a-linked-list/\",diff:\"Medium\",opt:\"O(1) time, O(1) space\",hint:\"Copy next node's value into current, skip over next.\",algo:\"1. node.val=node.next.val. 2. node.next=node.next.next.\"}\n      ]},\n      {label:\"Fast & Slow Pointers\",problems:[\n        {name:\"Middle of the Linked List\",url:\"https://leetcode.com/problems/middle-of-the-linked-list/\",diff:\"Easy\",opt:\"O(n) time, O(1) space\",hint:\"slow moves 1 step, fast moves 2. When fast reaches end, slow is at middle.\",algo:\"1. slow=fast=head. 2. While fast and fast.next: slow=slow.next, fast=fast.next.next. 3. Return slow.\"},\n        {name:\"Linked List Cycle\",url:\"https://leetcode.com/problems/linked-list-cycle/\",diff:\"Easy\",opt:\"O(n) time, O(1) space\",hint:\"Floyd's: slow+fast. If cycle, fast laps slow \u2192 they meet. If fast hits null \u2192 no cycle.\",algo:\"1. slow=fast=head. 2. While fast and fast.next: slow=slow.next, fast=fast.next.next. 3. If slow==fast: True. 4. Return False.\"},\n        {name:\"Linked List Cycle II\",url:\"https://leetcode.com/problems/linked-list-cycle-ii/\",diff:\"Medium\",opt:\"O(n) time, O(1) space\",hint:\"Find meeting point. Reset one to head. Move both 1 step. They meet at cycle start.\",algo:\"1. Find meeting point (slow/fast). 2. p2=head. 3. While slow!=p2: slow=slow.next, p2=p2.next. 4. Return slow.\"},\n        {name:\"Remove Nth Node From End\",url:\"https://leetcode.com/problems/remove-nth-node-from-end-of-list/\",diff:\"Medium\",opt:\"O(n) time, O(1) space\",hint:\"Gap of n between fast and slow. When fast reaches end, slow is right before the target.\",algo:\"1. dummy\u2192head. fast=slow=dummy. 2. Move fast n+1 steps. 3. Move both until fast=None. 4. slow.next=slow.next.next.\"}\n      ]},\n      {label:\"Reverse a Linked List\",problems:[\n        {name:\"Reverse Linked List\",url:\"https://leetcode.com/problems/reverse-linked-list/\",diff:\"Easy\",opt:\"O(n) time, O(1) space\",hint:\"prev=None, cur=head. Save next, reverse link, advance.\",algo:\"1. prev=None, cur=head. 2. While cur: nxt=cur.next, cur.next=prev, prev=cur, cur=nxt. 3. Return prev.\"},\n        {name:\"Reverse Linked List II\",url:\"https://leetcode.com/problems/reverse-linked-list-ii/\",diff:\"Medium\",opt:\"O(n) time, O(1) space\",hint:\"Walk to node before 'left'. Reverse exactly (right-left+1) nodes. Reconnect.\",algo:\"1. dummy\u2192head, before=dummy. 2. Walk to before left. 3. Reverse right-left+1 nodes from before.next. 4. Reconnect before.next and old left's next.\"},\n        {name:\"Swap Nodes in Pairs\",url:\"https://leetcode.com/problems/swap-nodes-in-pairs/\",diff:\"Medium\",opt:\"O(n) time, O(1) space\",hint:\"Process two nodes at a time. dummy head + prev pointer. Relink first,second,prev.\",algo:\"1. dummy\u2192head, prev=dummy. 2. While prev.next and prev.next.next: first=prev.next, second=first.next. 3. first.next=second.next, second.next=first, prev.next=second. 4. prev=first.\"},\n        {name:\"Reverse Nodes in k-Group\",url:\"https://leetcode.com/problems/reverse-nodes-in-k-group/\",diff:\"Hard\",opt:\"O(n) time, O(1) space\",hint:\"Check if k nodes exist. Reverse them. Connect to recursive result on rest.\",algo:\"1. Check k nodes exist. 2. Reverse k nodes (standard). 3. old-head.next = recurse(rest). 4. Return new head of reversed group.\"}\n      ]},\n      {label:\"Merge & Other\",problems:[\n        {name:\"Merge Two Sorted Lists\",url:\"https://leetcode.com/problems/merge-two-sorted-lists/\",diff:\"Easy\",opt:\"O(n+m) time, O(1) space\",hint:\"Dummy head + tail pointer. Compare fronts, attach smaller, advance.\",algo:\"1. dummy, tail=dummy. 2. While both: compare, attach smaller, advance that list + tail. 3. Attach remainder. 4. Return dummy.next.\"},\n        {name:\"Merge k Sorted Lists\",url:\"https://leetcode.com/problems/merge-k-sorted-lists/\",diff:\"Hard\",opt:\"O(n log k) time, O(k) space\",hint:\"Min-heap with head of each list. Pop smallest, attach to result, push its next.\",algo:\"1. heap with (val,i,node) for each list head. 2. dummy,tail. 3. Pop min, attach to tail. 4. If popped.next: push it. 5. Return dummy.next.\"},\n        {name:\"Add Two Numbers\",url:\"https://leetcode.com/problems/add-two-numbers/\",diff:\"Medium\",opt:\"O(max(n,m)) time+space\",hint:\"Digits in reverse so add normally. Track carry. While either list has nodes or carry remains.\",algo:\"1. dummy,cur,carry=0. 2. While l1 or l2 or carry: s=(l1.val or 0)+(l2.val or 0)+carry. 3. carry=s//10, new node s%10. 4. Advance l1,l2. Return dummy.next.\"},\n        {name:\"LRU Cache\",url:\"https://leetcode.com/problems/lru-cache/\",diff:\"Medium\",opt:\"O(1) per op, O(capacity) space\",hint:\"Doubly linked list (recency order) + dict (key\u2192node). On access: move to front. On overflow: evict from tail.\",algo:\"1. dummy head+tail sentinels. dict key\u2192node. 2. get: if exists, move to front, return val. 3. put: if exists update+move front. Else add to front. If over capacity: remove LRU (tail sentinel's prev).\"},\n        {name:\"Copy List with Random Pointer\",url:\"https://leetcode.com/problems/copy-list-with-random-pointer/\",diff:\"Medium\",opt:\"O(n) time, O(n) space\",hint:\"Pass 1: create clone map orig\u2192clone. Pass 2: wire next and random using map.\",algo:\"1. Walk: create clone for each node, map[orig]=clone. 2. Walk again: clone.next=map[orig.next], clone.random=map[orig.random]. 3. Return map[head].\"}\n      ]}\n    ]\n  },\n  {\n    title:\"05 \u2014 Stacks & Queues\", level:\"Core DSA\", count:12,\n    sections:[\n      {label:\"Stack Basics\",problems:[\n        {name:\"Valid Parentheses\",url:\"https://leetcode.com/problems/valid-parentheses/\",diff:\"Easy\",opt:\"O(n) time, O(n) space\",hint:\"Stack. Push open brackets. On close: check top matches. Valid if stack empty at end.\",algo:\"1. stack, matching={')':'(', ']':'[', '}':'{'}. 2. If open: push. 3. If close: if not stack or stack.pop()!=matching[c]: False. 4. Return stack==[]\"},\n        {name:\"Min Stack\",url:\"https://leetcode.com/problems/min-stack/\",diff:\"Medium\",opt:\"O(1) per op, O(n) space\",hint:\"Two stacks: value stack + min-tracking stack. Push min(val, current_min) to min stack.\",algo:\"1. stack, minStack. 2. push: stack.append(val), minStack.append(min(val,minStack[-1] if minStack else val)). 3. pop: both stacks. 4. getMin: minStack[-1].\"},\n        {name:\"Implement Queue using Stacks\",url:\"https://leetcode.com/problems/implement-queue-using-stacks/\",diff:\"Easy\",opt:\"Amortized O(1), O(n) space\",hint:\"inStack for push, outStack for pop/peek. When outStack empty: pour inStack into outStack.\",algo:\"1. inStack, outStack. 2. push: inStack.append. 3. pop/peek: if not outStack: pour all from inStack. Then pop/peek outStack.\"}\n      ]},\n      {label:\"Queue & Deque\",problems:[\n        {name:\"Design Circular Queue\",url:\"https://leetcode.com/problems/design-circular-queue/\",diff:\"Medium\",opt:\"O(1) per op, O(k) space\",hint:\"Fixed array + front + count. Insertion at (front+count)%k. Use modulo for wraparound.\",algo:\"1. arr[k], front=0, count=0. 2. enQueue: arr[(front+count)%k]=val, count++. 3. deQueue: front=(front+1)%k, count--. 4. Front: arr[front]. Rear: arr[(front+count-1)%k].\"},\n        {name:\"Implement Stack using Queues\",url:\"https://leetcode.com/problems/implement-stack-using-queues/\",diff:\"Easy\",opt:\"O(n) push, O(1) pop\",hint:\"After pushing, rotate queue: dequeue+enqueue all previous elements. Newest always at front.\",algo:\"1. push(x): queue.append(x), then rotate all prior elements behind x. 2. pop/top: queue.popleft()/queue[0].\"}\n      ]},\n      {label:\"Monotonic Stack\",problems:[\n        {name:\"Daily Temperatures\",url:\"https://leetcode.com/problems/daily-temperatures/\",diff:\"Medium\",opt:\"O(n) time, O(n) space\",hint:\"Monotonic decreasing stack of indices. On new temp: pop all with lower temp, set answer = current_idx - popped_idx.\",algo:\"1. res=[0]*n, stack=[]. 2. For i: while stack and T[i]>T[stack[-1]]: j=stack.pop(), res[j]=i-j. 3. stack.append(i).\"},\n        {name:\"Next Greater Element I\",url:\"https://leetcode.com/problems/next-greater-element-i/\",diff:\"Easy\",opt:\"O(n+m) time, O(n) space\",hint:\"Monotonic stack on nums2 \u2192 dict of next greater. Look up each nums1 value.\",algo:\"1. stack, nge={}. 2. For n in nums2: while stack and n>stack[-1]: nge[stack.pop()]=n. stack.append(n). 3. Remaining in stack: nge[v]=-1. 4. Return [nge.get(v,-1) for v in nums1].\"},\n        {name:\"Next Greater Element II\",url:\"https://leetcode.com/problems/next-greater-element-ii/\",diff:\"Medium\",opt:\"O(n) time, O(n) space\",hint:\"Circular \u2192 iterate twice (i%n). Only push to stack on first pass (i<n).\",algo:\"1. Iterate 2n with index i%n. 2. Same mono stack logic. 3. Only push during first pass (i<n).\"},\n        {name:\"Largest Rectangle in Histogram\",url:\"https://leetcode.com/problems/largest-rectangle-in-histogram/\",diff:\"Hard\",opt:\"O(n) time, O(n) space\",hint:\"Monotonic increasing stack. When shorter bar found, pop and compute area using current index as right bound, new top as left bound.\",algo:\"1. stack, heights+=[0] (sentinel). 2. For i: while stack and h[i]<h[stack[-1]]: j=stack.pop(), w=i if not stack else i-stack[-1]-1, res=max(res,h[j]*w). 3. stack.append(i).\"}\n      ]},\n      {label:\"Stack-based Evaluation\",problems:[\n        {name:\"Evaluate Reverse Polish Notation\",url:\"https://leetcode.com/problems/evaluate-reverse-polish-notation/\",diff:\"Medium\",opt:\"O(n) time, O(n) space\",hint:\"Stack. Numbers: push. Operators: pop two, apply, push result.\",algo:\"1. stack. 2. If number: push. 3. If op: b=pop, a=pop, push a op b. 4. Return stack[0].\"},\n        {name:\"Basic Calculator II\",url:\"https://leetcode.com/problems/basic-calculator-ii/\",diff:\"Medium\",opt:\"O(n) time, O(n) space\",hint:\"Track current number and last operator. +/-: push signed. */\u00f7: pop and compute, push back. Sum stack at end.\",algo:\"1. stack, num=0, op='+'. 2. Scan: build num. On op or end: if '+' push num, '-' push -num, '*' push pop*num, '/' push int(pop/num). 3. op=current, num=0. 4. Return sum(stack).\"}\n      ]}\n    ]\n  },\n  {\n    title:\"06 \u2014 Binary Search\", level:\"Core DSA\", count:12,\n    sections:[\n      {label:\"Classic\",problems:[\n        {name:\"Binary Search\",url:\"https://leetcode.com/problems/binary-search/\",diff:\"Easy\",opt:\"O(log n) time, O(1) space\",hint:\"low/high pointers. mid=(low+high)//2. Compare. Adjust.\",algo:\"1. low=0,high=n-1. 2. mid=(l+h)//2. 3. If nums[mid]==target: return mid. 4. If <: low=mid+1. Else: high=mid-1. 5. Return -1.\"},\n        {name:\"Search Insert Position\",url:\"https://leetcode.com/problems/search-insert-position/\",diff:\"Easy\",opt:\"O(log n) time, O(1) space\",hint:\"Binary search. If not found, return low \u2014 that's the insert position.\",algo:\"Same as binary search. On exit (not found): return low.\"}\n      ]},\n      {label:\"Find Leftmost / Rightmost\",problems:[\n        {name:\"Find First and Last Position of Element\",url:\"https://leetcode.com/problems/find-first-and-last-position-of-element-in-sorted-array/\",diff:\"Medium\",opt:\"O(log n) time, O(1) space\",hint:\"Binary search twice: once biased left (keep going left on match), once biased right.\",algo:\"1. findLeft: when nums[mid]==target, record mid, high=mid-1. 2. findRight: when ==, record mid, low=mid+1. 3. Return [left,right] or [-1,-1].\"}\n      ]},\n      {label:\"Binary Search on Answer\",problems:[\n        {name:\"Koko Eating Bananas\",url:\"https://leetcode.com/problems/koko-eating-bananas/\",diff:\"Medium\",opt:\"O(n log m) time, O(1) space\",hint:\"Binary search on speed (1 to max). For given speed: can she finish in h hours? Find minimum valid speed.\",algo:\"1. low=1,high=max(piles). 2. For mid: hours=sum(ceil(p/mid) for p in piles). 3. If <=h: ans=mid, high=mid-1. 4. Else: low=mid+1.\"},\n        {name:\"Capacity To Ship Packages Within D Days\",url:\"https://leetcode.com/problems/capacity-to-ship-packages-within-d-days/\",diff:\"Medium\",opt:\"O(n log(sum)) time, O(1) space\",hint:\"Binary search on capacity. low=max(weights), high=sum(weights). Greedy simulate days needed.\",algo:\"1. low=max(w),high=sum(w). 2. For mid: greedily count days. 3. If <=D: ans=mid, high=mid-1. Else: low=mid+1.\"},\n        {name:\"Split Array Largest Sum\",url:\"https://leetcode.com/problems/split-array-largest-sum/\",diff:\"Hard\",opt:\"O(n log(sum)) time, O(1) space\",hint:\"Binary search on max subarray sum. Greedy count splits needed. Find minimum max.\",algo:\"1. low=max(nums),high=sum(nums). 2. For mid: greedily count splits (no subarray >mid). 3. If splits<=k: ans=mid, high=mid-1. Else: low=mid+1.\"}\n      ]},\n      {label:\"Search in Rotated Array\",problems:[\n        {name:\"Search in Rotated Sorted Array\",url:\"https://leetcode.com/problems/search-in-rotated-sorted-array/\",diff:\"Medium\",opt:\"O(log n) time, O(1) space\",hint:\"Determine which half is sorted, check if target in that range.\",algo:\"1. At mid: if nums[low]<=nums[mid] (left sorted): if low<=target<mid \u2192 search left. Else right. 2. Else (right sorted): if mid<target<=high \u2192 search right. Else left.\"},\n        {name:\"Search in Rotated Sorted Array II\",url:\"https://leetcode.com/problems/search-in-rotated-sorted-array-ii/\",diff:\"Medium\",opt:\"O(log n) avg, O(n) worst\",hint:\"Same as I, but when nums[low]==nums[mid]==nums[high]: shrink both ends by 1.\",algo:\"Add: if nums[low]==nums[mid]==nums[high]: low++, high--. Else same as I.\"},\n        {name:\"Find Minimum in Rotated Sorted Array\",url:\"https://leetcode.com/problems/find-minimum-in-rotated-sorted-array/\",diff:\"Medium\",opt:\"O(log n) time, O(1) space\",hint:\"Compare nums[mid] to nums[high]. If mid>high: min is right. Else: min is left including mid.\",algo:\"1. low=0,high=n-1. 2. While low<high: mid=(l+h)//2. 3. If nums[mid]>nums[high]: low=mid+1. Else: high=mid. 4. Return nums[low].\"}\n      ]},\n      {label:\"2D Binary Search\",problems:[\n        {name:\"Search a 2D Matrix\",url:\"https://leetcode.com/problems/search-a-2d-matrix/\",diff:\"Medium\",opt:\"O(log(m\u00b7n)) time, O(1) space\",hint:\"Flat binary search. mid\u2192row=mid//cols, col=mid%cols.\",algo:\"1. low=0,high=rows*cols-1. 2. mid=(l+h)//2, row=mid//cols, col=mid%cols. 3. Compare+adjust.\"},\n        {name:\"Search a 2D Matrix II\",url:\"https://leetcode.com/problems/search-a-2d-matrix-ii/\",diff:\"Medium\",opt:\"O(m+n) time, O(1) space\",hint:\"Start top-right. Bigger than target \u2192 move left. Smaller \u2192 move down.\",algo:\"1. row=0,col=cols-1. 2. While in bounds: if ==target: True. 3. If >: col--. 4. If <: row++. 5. Return False.\"},\n        {name:\"Median of Two Sorted Arrays\",url:\"https://leetcode.com/problems/median-of-two-sorted-arrays/\",diff:\"Hard\",opt:\"O(log(min(n,m))) time, O(1) space\",hint:\"Binary search on smaller array's partition. Correct when left1<=right2 AND left2<=right1.\",algo:\"Ensure nums1 shorter. Binary search on partition i in nums1. j=(m+n+1)//2-i. Check boundaries. Adjust. Compute median from 4 boundary values.\"}\n      ]}\n    ]\n  },\n  {\n    title:\"07 \u2014 Trees\", level:\"Intermediate\", count:25,\n    sections:[\n      {label:\"Basics\",problems:[\n        {name:\"Maximum Depth of Binary Tree\",url:\"https://leetcode.com/problems/maximum-depth-of-binary-tree/\",diff:\"Easy\",opt:\"O(n) time, O(h) space\",hint:\"1 + max(depth(left), depth(right)). Base: null=0.\",algo:\"If not node: return 0. Return 1+max(maxDepth(l),maxDepth(r)).\"},\n        {name:\"Same Tree\",url:\"https://leetcode.com/problems/same-tree/\",diff:\"Easy\",opt:\"O(n) time, O(h) space\",hint:\"Both null=True. One null=False. Values differ=False. Recurse both sides.\",algo:\"If both None: True. If one None or vals differ: False. Return sameTree(l,l2) and sameTree(r,r2).\"},\n        {name:\"Invert Binary Tree\",url:\"https://leetcode.com/problems/invert-binary-tree/\",diff:\"Easy\",opt:\"O(n) time, O(h) space\",hint:\"Swap left and right, recurse on both.\",algo:\"If not node: return. node.left,node.right=node.right,node.left. Recurse both.\"},\n        {name:\"Symmetric Tree\",url:\"https://leetcode.com/problems/symmetric-tree/\",diff:\"Easy\",opt:\"O(n) time, O(h) space\",hint:\"isMirror(left,right): vals match AND isMirror(l.left,r.right) AND isMirror(l.right,r.left).\",algo:\"isMirror(l,r): if both None:True. If one None or vals differ:False. return isMirror(l.left,r.right) and isMirror(l.right,r.left).\"}\n      ]},\n      {label:\"DFS Traversals\",problems:[\n        {name:\"Binary Tree Inorder Traversal\",url:\"https://leetcode.com/problems/binary-tree-inorder-traversal/\",diff:\"Easy\",opt:\"O(n) time, O(h) space\",hint:\"Left, root, right. Iterative: push left chain, pop+visit, go right.\",algo:\"Recursive: inorder(l), append val, inorder(r). Iterative: push lefts, pop, append, right.\"},\n        {name:\"Binary Tree Preorder Traversal\",url:\"https://leetcode.com/problems/binary-tree-preorder-traversal/\",diff:\"Easy\",opt:\"O(n) time, O(h) space\",hint:\"Root, left, right. Iterative: pop, append, push right then left.\",algo:\"Iterative: stack=[root]. Pop, append val, push right then left (LIFO so left processed first).\"},\n        {name:\"Binary Tree Postorder Traversal\",url:\"https://leetcode.com/problems/binary-tree-postorder-traversal/\",diff:\"Easy\",opt:\"O(n) time, O(h) space\",hint:\"Trick: modified preorder (root,right,left) then reverse result.\",algo:\"Do preorder pushing right-first, collect vals, reverse at end.\"}\n      ]},\n      {label:\"BFS / Level Order\",problems:[\n        {name:\"Binary Tree Level Order Traversal\",url:\"https://leetcode.com/problems/binary-tree-level-order-traversal/\",diff:\"Medium\",opt:\"O(n) time, O(n) space\",hint:\"BFS queue. Process one full level at a time by tracking queue size before adding children.\",algo:\"1. queue=[root]. 2. While queue: size=len(queue), level=[]. 3. Pop size nodes, add vals, push children. 4. result.append(level).\"},\n        {name:\"Binary Tree Zigzag Level Order\",url:\"https://leetcode.com/problems/binary-tree-zigzag-level-order-traversal/\",diff:\"Medium\",opt:\"O(n) time, O(n) space\",hint:\"Same BFS, alternate direction flag. Reverse every other level before appending.\",algo:\"BFS + left_to_right flag. If not left_to_right: level.reverse(). Flip flag each level.\"},\n        {name:\"Binary Tree Right Side View\",url:\"https://leetcode.com/problems/binary-tree-right-side-view/\",diff:\"Medium\",opt:\"O(n) time, O(n) space\",hint:\"BFS level order. Last node per level is visible from right.\",algo:\"BFS. For each level, the LAST node popped is the answer for that level.\"}\n      ]},\n      {label:\"BST\",problems:[\n        {name:\"Search in a Binary Search Tree\",url:\"https://leetcode.com/problems/search-in-a-binary-search-tree/\",diff:\"Easy\",opt:\"O(h) time, O(1) iterative\",hint:\"BST property: target<val \u2192 left. target>val \u2192 right.\",algo:\"While node: if ==val: return. If <: go left. If >: go right. Return None.\"},\n        {name:\"Insert into a BST\",url:\"https://leetcode.com/problems/insert-into-a-binary-search-tree/\",diff:\"Medium\",opt:\"O(h) time, O(h) space\",hint:\"Walk to null spot using BST property. Create node there.\",algo:\"If not node: return Node(val). If val<node.val: node.left=insert(l,val). Else: node.right=insert(r,val). Return node.\"},\n        {name:\"Delete Node in a BST\",url:\"https://leetcode.com/problems/delete-node-in-a-bst/\",diff:\"Medium\",opt:\"O(h) time, O(h) space\",hint:\"3 cases: no children (remove), one child (replace), two children (inorder successor replaces value).\",algo:\"Find node. 1. No left: return right. 2. No right: return left. 3. Find inorder successor (leftmost of right). Copy its val. Delete successor from right subtree.\"},\n        {name:\"Validate Binary Search Tree\",url:\"https://leetcode.com/problems/validate-binary-search-tree/\",diff:\"Medium\",opt:\"O(n) time, O(h) space\",hint:\"Track (min,max) range per node. Not just children \u2014 full range constraint.\",algo:\"validate(node, lo, hi): if not node: True. If node.val<=lo or >=hi: False. Return validate(l,lo,val) and validate(r,val,hi). Start with (-inf,+inf).\"},\n        {name:\"Kth Smallest Element in a BST\",url:\"https://leetcode.com/problems/kth-smallest-element-in-a-bst/\",diff:\"Medium\",opt:\"O(h+k) time, O(h) space\",hint:\"Inorder traversal visits BST in sorted order. Stop at kth node.\",algo:\"Inorder traversal with counter. When counter==k: record answer, return early.\"}\n      ]},\n      {label:\"Path Problems\",problems:[\n        {name:\"Path Sum\",url:\"https://leetcode.com/problems/path-sum/\",diff:\"Easy\",opt:\"O(n) time, O(h) space\",hint:\"Subtract node value from target going down. At leaf: check if remaining==0.\",algo:\"If not node: False. If leaf and node.val==target: True. Return pathSum(l,t-val) or pathSum(r,t-val).\"},\n        {name:\"Path Sum II\",url:\"https://leetcode.com/problems/path-sum-ii/\",diff:\"Medium\",opt:\"O(n\u00b2) worst time, O(h) space\",hint:\"Same as Path Sum but track path (backtracking). At valid leaf: copy path to results.\",algo:\"DFS: append val, subtract. At leaf with rem==0: results.append(path.copy()). Recurse l,r. path.pop() (backtrack).\"},\n        {name:\"Binary Tree Maximum Path Sum\",url:\"https://leetcode.com/problems/binary-tree-maximum-path-sum/\",diff:\"Hard\",opt:\"O(n) time, O(h) space\",hint:\"At each node: consider path through both sides (update global max). Return only one side to parent.\",algo:\"maxGain(node): lGain=max(0,maxGain(l)), rGain=max(0,maxGain(r)). Update globalMax=max(globalMax, val+lGain+rGain). Return val+max(lGain,rGain).\"}\n      ]},\n      {label:\"LCA & Construction\",problems:[\n        {name:\"LCA of a BST\",url:\"https://leetcode.com/problems/lowest-common-ancestor-of-a-binary-search-tree/\",diff:\"Medium\",opt:\"O(h) time, O(1) space\",hint:\"Both <val \u2192 go left. Both >val \u2192 go right. Otherwise current = LCA.\",algo:\"While node: if p.val<node.val and q.val<node.val: go left. If both >: go right. Else: return node.\"},\n        {name:\"LCA of a Binary Tree\",url:\"https://leetcode.com/problems/lowest-common-ancestor-of-a-binary-tree/\",diff:\"Medium\",opt:\"O(n) time, O(h) space\",hint:\"If node is null or equals p or q: return node. Both subtrees non-null \u2192 current is LCA. Else return non-null.\",algo:\"If not node or node==p or node==q: return node. l=lca(left), r=lca(right). If l and r: return node. Return l or r.\"},\n        {name:\"Construct Tree from Preorder+Inorder\",url:\"https://leetcode.com/problems/construct-binary-tree-from-preorder-and-inorder-traversal/\",diff:\"Medium\",opt:\"O(n) time, O(n) space\",hint:\"First of preorder = root. Find in inorder \u2192 splits left/right subtrees. Recurse.\",algo:\"Dict: inorder val\u2192idx. preorder[0]=root. rootIdx in inorder. Left: preorder[1:1+leftSize], inorder[:rootIdx]. Right: rest.\"},\n        {name:\"Serialize and Deserialize Binary Tree\",url:\"https://leetcode.com/problems/serialize-and-deserialize-binary-tree/\",diff:\"Hard\",opt:\"O(n) time, O(n) space\",hint:\"Serialize: preorder with 'null' placeholders. Deserialize: consume same sequence.\",algo:\"Serialize: preorder, null\u2192'#', join with ','. Deserialize: split, pointer. If '#': null. Else: node, recurse left then right.\"}\n      ]},\n      {label:\"Balanced & Diameter\",problems:[\n        {name:\"Balanced Binary Tree\",url:\"https://leetcode.com/problems/balanced-binary-tree/\",diff:\"Easy\",opt:\"O(n) time, O(h) space\",hint:\"Bottom-up: return -1 if unbalanced. Avoids O(n\u00b2) naive approach.\",algo:\"helper(node): if not node: 0. l=helper(left), r=helper(right). If l==-1 or r==-1 or abs(l-r)>1: return -1. Return 1+max(l,r). Call from root.\"},\n        {name:\"Diameter of Binary Tree\",url:\"https://leetcode.com/problems/diameter-of-binary-tree/\",diff:\"Easy\",opt:\"O(n) time, O(h) space\",hint:\"Diameter through node = leftHeight + rightHeight. Update global max at each node.\",algo:\"helper(node): if not: 0. l,r=helper(l),helper(r). res=max(res, l+r). Return 1+max(l,r).\"},\n        {name:\"Flatten Binary Tree to Linked List\",url:\"https://leetcode.com/problems/flatten-binary-tree-to-linked-list/\",diff:\"Medium\",opt:\"O(n) time, O(1) extra\",hint:\"Reverse postorder (right,left,root). At each node: node.right=prev, node.left=None, prev=node.\",algo:\"prev=None. Traverse in reverse postorder. At node: node.right=prev, node.left=None, prev=node.\"}\n      ]}\n    ]\n  },\n  {\n    title:\"08 \u2014 Heaps & Priority Queue\", level:\"Intermediate\", count:10,\n    sections:[\n      {label:\"Heap Basics\",problems:[\n        {name:\"Last Stone Weight\",url:\"https://leetcode.com/problems/last-stone-weight/\",diff:\"Easy\",opt:\"O(n log n) time, O(n) space\",hint:\"Max-heap (negate for Python). Pop two largest, push difference if non-zero.\",algo:\"1. heap=[-s for s in stones], heapify. 2. While len>1: a,b=-heappop,-heappop. If a!=b: heappush(-(a-b)). 3. Return -heap[0] if heap else 0.\"},\n        {name:\"Kth Largest Element in an Array\",url:\"https://leetcode.com/problems/kth-largest-element-in-an-array/\",diff:\"Medium\",opt:\"O(n log k) time, O(k) space\",hint:\"Min-heap of size k. Push all elements, pop when >k. Top = kth largest.\",algo:\"1. heap=[]. 2. For num: heappush(heap,num). 3. If len>k: heappop. 4. Return heap[0].\"},\n        {name:\"Top K Frequent Elements\",url:\"https://leetcode.com/problems/top-k-frequent-elements/\",diff:\"Medium\",opt:\"O(n log k) time, O(n) space\",hint:\"Freq dict + min-heap of size k by frequency.\",algo:\"1. freq=Counter(nums). 2. heap=[]. 3. For v,f: heappush(heap,(f,v)). If len>k: heappop. 4. Return [v for _,v in heap].\"},\n        {name:\"K Closest Points to Origin\",url:\"https://leetcode.com/problems/k-closest-points-to-origin/\",diff:\"Medium\",opt:\"O(n log k) time, O(k) space\",hint:\"Max-heap of size k by distance (negate). Pop farthest when >k.\",algo:\"1. heap=[]. 2. For x,y: d=x*x+y*y. heappush(heap,(-d,(x,y))). If len>k: heappop. 3. Return [p for _,p in heap].\"},\n        {name:\"Kth Largest Element in a Stream\",url:\"https://leetcode.com/problems/kth-largest-element-in-a-stream/\",diff:\"Easy\",opt:\"O(log k) per add, O(k) space\",hint:\"Min-heap of size k. Top is always kth largest.\",algo:\"1. Init: build heap from nums, trim to k. 2. add(val): heappush, if len>k: heappop. 3. Return heap[0].\"}\n      ]},\n      {label:\"Advanced Heap\",problems:[\n        {name:\"Merge k Sorted Lists\",url:\"https://leetcode.com/problems/merge-k-sorted-lists/\",diff:\"Hard\",opt:\"O(n log k) time, O(k) space\",hint:\"Min-heap with (val, list_idx, node). Pop min, push next node from same list.\",algo:\"heap with (val,i,node) for each head. dummy+tail. Pop min, attach, push next if exists.\"},\n        {name:\"Task Scheduler\",url:\"https://leetcode.com/problems/task-scheduler/\",diff:\"Medium\",opt:\"O(n) time, O(1) space\",hint:\"Formula: (maxFreq-1)*(n+1)+maxCount. Answer = max(formula, len(tasks)).\",algo:\"1. freq=Counter. 2. maxFreq=max. 3. maxCount=count of tasks with maxFreq. 4. baseline=(maxFreq-1)*(n+1)+maxCount. 5. Return max(baseline, len(tasks)).\"},\n        {name:\"Find Median from Data Stream\",url:\"https://leetcode.com/problems/find-median-from-data-stream/\",diff:\"Hard\",opt:\"O(log n) add, O(1) median, O(n) space\",hint:\"Two heaps: max-heap (lower half) + min-heap (upper half). Keep balanced.\",algo:\"1. lo (max-heap, negate), hi (min-heap). 2. addNum: push to lo, move lo's max to hi, if len(hi)>len(lo): move hi's min to lo. 3. findMedian: if equal sizes: avg. Else: lo's max.\"},\n        {name:\"IPO\",url:\"https://leetcode.com/problems/ipo/\",diff:\"Hard\",opt:\"O(n log n) time, O(n) space\",hint:\"Sort by capital. Max-heap for profit. Each round: push all affordable projects, pop most profitable.\",algo:\"1. Sort by capital. 2. ptr=0, maxheap=[]. 3. For k rounds: push all affordable to maxheap, pop max profit. 4. If empty: stop.\"},\n        {name:\"Smallest Range Covering K Lists\",url:\"https://leetcode.com/problems/smallest-range-covering-elements-from-k-lists/\",diff:\"Hard\",opt:\"O(n log k) time, O(k) space\",hint:\"Min-heap with one from each list. Track current max across heap. Pop min, update range (min,curMax), push next from same list.\",algo:\"1. heap=(val,list_i,elem_i) for each list's first elem. curMax=max. 2. Pop min, update best range. Push next from same list. Update curMax. 3. Stop when any list exhausted.\"}\n      ]}\n    ]\n  },\n  {title:\"09 \u2014 Graphs\", level:\"Intermediate\", count:43, sections:[{label:\"See full problem sheet \u2014 43 problems covering DFS/BFS/Dijkstra/Union-Find/Topological Sort\",problems:[{name:\"(43 problems \u2014 load from full sheet)\",url:\"\",diff:\"Medium\",opt:\"See full problem sheet\",hint:\"Phases: DFS, BFS, Cycle Detection, Topological Sort, Union-Find, Dijkstra, Bellman-Ford, MST, Bipartite, Clone Graph\",algo:\"Practice order: Number of Islands \u2192 Course Schedule \u2192 Clone Graph \u2192 Word Ladder \u2192 Network Delay Time \u2192 Redundant Connection \u2192 Accounts Merge\"}]}]},\n  {title:\"10 \u2014 Backtracking\", level:\"Intermediate\", count:12, sections:[{label:\"Core problems\",problems:[\n    {name:\"Subsets\",url:\"https://leetcode.com/problems/subsets/\",diff:\"Medium\",opt:\"O(n\u00b72\u207f) time, O(n) space\",hint:\"At each element: include or not. Recurse both. Add current subset at each call.\",algo:\"DFS(start,path): results.append(path[:]). For i from start: path.append(nums[i]), DFS(i+1,path), path.pop().\"},\n    {name:\"Permutations\",url:\"https://leetcode.com/problems/permutations/\",diff:\"Medium\",opt:\"O(n\u00b7n!) time, O(n) space\",hint:\"At each step try all unused numbers. used[] tracker. Backtrack after each choice.\",algo:\"DFS(path,used): if len==n: results.append(path[:]). For i: if not used[i]: used[i]=True, path.append, DFS, path.pop, used[i]=False.\"},\n    {name:\"Combination Sum\",url:\"https://leetcode.com/problems/combination-sum/\",diff:\"Medium\",opt:\"O(2^target) worst, O(target) space\",hint:\"Repetition allowed \u2192 recurse with same index. Stop when remaining<0.\",algo:\"DFS(start,path,rem): if rem==0: results.append(path[:]). For i from start: if cands[i]<=rem: add, DFS(i,path,rem-cands[i]), pop.\"},\n    {name:\"Word Search\",url:\"https://leetcode.com/problems/word-search/\",diff:\"Medium\",opt:\"O(m\u00b7n\u00b74^L) time, O(L) space\",hint:\"DFS from each matching first char. Mark visited (overwrite). Backtrack (restore).\",algo:\"DFS(r,c,idx): if idx==len(word): True. If OOB or board!=word[idx]: False. Mark visited. Recurse 4 dirs. Restore. Return result.\"},\n    {name:\"N-Queens\",url:\"https://leetcode.com/problems/n-queens/\",diff:\"Hard\",opt:\"O(n!) time, O(n) space\",hint:\"Place one queen per row. Track cols, diagonals (row-col, row+col). Backtrack.\",algo:\"DFS(row,cols,d1,d2,board): if row==n: record. For col: if not in cols/d1/d2: place, recurse, remove.\"},\n    {name:\"Palindrome Partitioning\",url:\"https://leetcode.com/problems/palindrome-partitioning/\",diff:\"Medium\",opt:\"O(n\u00b72\u207f) time, O(n) space\",hint:\"Try every prefix. If palindrome: add to path, recurse on rest. Backtrack.\",algo:\"DFS(start,path): if start==n: results.append(path[:]). For end from start+1: if isPalin(s[start:end]): path.append, DFS(end,path), path.pop.\"},\n    {name:\"Sudoku Solver\",url:\"https://leetcode.com/problems/sudoku-solver/\",diff:\"Hard\",opt:\"O(9^(empty cells)) worst, O(1) extra\",hint:\"Find empty cell. Try 1-9, check valid (row/col/box). Recurse. If fails: backtrack.\",algo:\"Find '.'. If none: solved. For d in '1'-'9': if valid: place, recurse. If recurse True: return True. Else: remove d. Return False.\"}\n  ]}]},\n  {title:\"11 \u2014 Dynamic Programming\", level:\"Advanced\", count:51, sections:[{label:\"51 problems \u2014 1D DP, 2D DP, Knapsack, String DP, Interval DP, Tree DP, Bitmask DP, Stock DP\",problems:[\n    {name:\"Climbing Stairs\",url:\"https://leetcode.com/problems/climbing-stairs/\",diff:\"Easy\",opt:\"O(n) time, O(1) space\",hint:\"ways(n) = ways(n-1) + ways(n-2). It's Fibonacci.\",algo:\"prev2=1, prev1=2. For i in 3..n: cur=prev1+prev2, prev2=prev1, prev1=cur. Return prev1.\"},\n    {name:\"House Robber\",url:\"https://leetcode.com/problems/house-robber/\",diff:\"Medium\",opt:\"O(n) time, O(1) space\",hint:\"At each house: rob (prev2+val) or skip (prev1). Track two rolling values.\",algo:\"prev2=prev1=0. For val: cur=max(prev1, prev2+val). prev2=prev1, prev1=cur. Return prev1.\"},\n    {name:\"Coin Change\",url:\"https://leetcode.com/problems/coin-change/\",diff:\"Medium\",opt:\"O(amount\u00b7coins) time, O(amount) space\",hint:\"dp[i]=min coins for amount i. For each amount: try every coin.\",algo:\"dp=[inf]*(amount+1), dp[0]=0. For i in 1..amount: for coin: if coin<=i: dp[i]=min(dp[i],dp[i-coin]+1). Return dp[amount] if not inf else -1.\"},\n    {name:\"Longest Increasing Subsequence\",url:\"https://leetcode.com/problems/longest-increasing-subsequence/\",diff:\"Medium\",opt:\"O(n log n) w/ binary search\",hint:\"Maintain 'tails': smallest tail for increasing subsequences of each length. Binary search where each new num fits.\",algo:\"tails=[]. For num: bisect_left for pos. If pos==len(tails): append. Else: tails[pos]=num. Return len(tails).\"},\n    {name:\"Longest Common Subsequence\",url:\"https://leetcode.com/problems/longest-common-subsequence/\",diff:\"Medium\",opt:\"O(n\u00b7m) time, O(n\u00b7m) space\",hint:\"dp[i][j] = LCS of first i chars of s1 and j chars of s2.\",algo:\"dp[i][j] = dp[i-1][j-1]+1 if chars match, else max(dp[i-1][j], dp[i][j-1]).\"},\n    {name:\"Partition Equal Subset Sum\",url:\"https://leetcode.com/problems/partition-equal-subset-sum/\",diff:\"Medium\",opt:\"O(n\u00b7sum) time, O(sum) space\",hint:\"0/1 knapsack. Can we find subset summing to total//2? Iterate backwards to avoid reuse.\",algo:\"If total odd: False. target=total//2. dp=[F]*(target+1), dp[0]=T. For num: for j from target down to num: dp[j]|=dp[j-num]. Return dp[target].\"}\n  ]}]},\n  {title:\"12 \u2014 Tries\", level:\"Advanced\", count:5, sections:[{label:\"Trie problems\",problems:[\n    {name:\"Implement Trie (Prefix Tree)\",url:\"https://leetcode.com/problems/implement-trie-prefix-tree/\",diff:\"Medium\",opt:\"O(L) per op, O(total chars) space\",hint:\"TrieNode: children dict + isEnd flag. Insert: create nodes. Search: walk + check isEnd. startsWith: walk.\",algo:\"TrieNode: {children:{}, isEnd:False}. Insert: for char: if not in children: children[char]=TrieNode(). Move to child. Mark isEnd. Search same but return isEnd at end.\"},\n    {name:\"Design Add and Search Words Data Structure\",url:\"https://leetcode.com/problems/design-add-and-search-words-data-structure/\",diff:\"Medium\",opt:\"O(L) add, O(26^L) search worst\",hint:\"Same trie but '.' = wildcard. Try all children on '.'.\",algo:\"Search recursive: if '.': try all children. If char: walk one path. Base: at end return isEnd.\"},\n    {name:\"Word Search II\",url:\"https://leetcode.com/problems/word-search-ii/\",diff:\"Hard\",opt:\"O(m\u00b7n\u00b74^L) time, O(total chars) space\",hint:\"Build trie from all words. DFS grid + trie simultaneously. Prune when no trie path.\",algo:\"Build trie. For each cell: DFS(r,c,trieNode). If not in children: stop. If isEnd: add word. Mark visited, recurse 4 dirs, restore.\"},\n    {name:\"Replace Words\",url:\"https://leetcode.com/problems/replace-words/\",diff:\"Medium\",opt:\"O(total chars) time+space\",hint:\"Trie from roots. For each word: walk trie, stop at first isEnd = shortest root.\",algo:\"Build trie from roots. For each word: walk char by char. If isEnd hit: use prefix so far. Else keep word.\"},\n    {name:\"Maximum XOR of Two Numbers in an Array\",url:\"https://leetcode.com/problems/maximum-xor-of-two-numbers-in-an-array/\",diff:\"Medium\",opt:\"O(n\u00b732) time+space\",hint:\"Binary trie (MSB first). For each number: walk trie taking opposite bit greedily.\",algo:\"Build binary trie (bit by bit MSB first). For each num: greedily walk opposite direction. XOR = bits where we took opposite. Track max.\"}\n  ]}]},\n  {title:\"13 \u2014 Bit Manipulation\", level:\"Advanced\", count:10, sections:[{label:\"Bit problems\",problems:[\n    {name:\"Number of 1 Bits\",url:\"https://leetcode.com/problems/number-of-1-bits/\",diff:\"Easy\",opt:\"O(1) time+space\",hint:\"n & (n-1) clears lowest set bit. Count how many times before n=0.\",algo:\"count=0. While n: n&=n-1, count++. Return count.\"},\n    {name:\"Counting Bits\",url:\"https://leetcode.com/problems/counting-bits/\",diff:\"Easy\",opt:\"O(n) time, O(n) space\",hint:\"dp[i] = dp[i>>1] + (i&1). Bits in i = bits in i//2, plus last bit.\",algo:\"dp=[0]*(n+1). For i in 1..n: dp[i]=dp[i>>1]+(i&1). Return dp.\"},\n    {name:\"Single Number\",url:\"https://leetcode.com/problems/single-number/\",diff:\"Easy\",opt:\"O(n) time, O(1) space\",hint:\"XOR all. a^a=0, a^0=a. Pairs cancel.\",algo:\"Return reduce(xor, nums).\"},\n    {name:\"Missing Number\",url:\"https://leetcode.com/problems/missing-number/\",diff:\"Easy\",opt:\"O(n) time, O(1) space\",hint:\"XOR all indices and values. Paired values cancel, missing remains. Or: n*(n+1)//2 - sum.\",algo:\"res=n. For i,v in enumerate(nums): res^=i^v. Return res.\"},\n    {name:\"Reverse Bits\",url:\"https://leetcode.com/problems/reverse-bits/\",diff:\"Easy\",opt:\"O(1) time+space\",hint:\"32 iterations: shift result left, OR in lowest bit of n, shift n right.\",algo:\"res=0. For _ in range(32): res=(res<<1)|(n&1), n>>=1. Return res.\"},\n    {name:\"Power of Two\",url:\"https://leetcode.com/problems/power-of-two/\",diff:\"Easy\",opt:\"O(1) time+space\",hint:\"Power of two has exactly one bit set. n&(n-1)==0 clears it. Check n>0.\",algo:\"Return n>0 and (n&(n-1))==0.\"},\n    {name:\"Sum of Two Integers\",url:\"https://leetcode.com/problems/sum-of-two-integers/\",diff:\"Medium\",opt:\"O(1) time+space\",hint:\"XOR=sum without carry. AND<<1=carry. Repeat until carry=0.\",algo:\"While b: a,b = a^b, (a&b)<<1. Return a. (Python: mask to 32-bit for negatives.)\"},\n    {name:\"Single Number II\",url:\"https://leetcode.com/problems/single-number-ii/\",diff:\"Medium\",opt:\"O(n) time, O(1) space\",hint:\"Every number appears 3x except one. Track bits mod 3 with two variables ones and twos.\",algo:\"ones=twos=0. For num: ones=(ones^num)&~twos, twos=(twos^num)&~ones. Return ones.\"},\n    {name:\"Power of Four\",url:\"https://leetcode.com/problems/power-of-four/\",diff:\"Easy\",opt:\"O(1) time+space\",hint:\"Power of two AND single bit at even position (use mask 0x55555555).\",algo:\"Return n>0 and (n&(n-1))==0 and (n&0x55555555)!=0.\"},\n    {name:\"Subsets (bitmask)\",url:\"https://leetcode.com/problems/subsets/\",diff:\"Medium\",opt:\"O(n\u00b72\u207f) time, O(n) space\",hint:\"For i in 0..2^n: use bitmask to pick elements (bit j set = include nums[j]).\",algo:\"For mask in range(1<<n): subset=[nums[j] for j in range(n) if mask&(1<<j)]. Append subset.\"}\n  ]}]},\n  {title:\"14 \u2014 Advanced Data Structures\", level:\"MAANG Level\", count:6, sections:[{label:\"Segment Tree, Fenwick Tree, Sparse Table\",problems:[\n    {name:\"Range Sum Query \u2014 Mutable\",url:\"https://leetcode.com/problems/range-sum-query-mutable/\",diff:\"Medium\",opt:\"O(log n) per op, O(n) space\",hint:\"Segment tree. Build: each node = sum of range. Update: propagate up. Query: decompose range.\",algo:\"Build tree[2n]. Update: tree[n+i]=val, propagate up. Query: sum tree nodes covering [l,r].\"},\n    {name:\"Range Sum Query 2D \u2014 Mutable\",url:\"https://leetcode.com/problems/range-sum-query-2d-mutable/\",diff:\"Hard\",opt:\"O(log n\u00b7log m) per op\",hint:\"2D Fenwick tree. Update both dims. sumRegion via inclusion-exclusion with 4 queries.\",algo:\"2D BIT. update(r,c,delta): BIT updates in both row and col dims. query(r,c): prefix sum. sumRegion: query(r2,c2)-query(r1-1,c2)-query(r2,c1-1)+query(r1-1,c1-1).\"},\n    {name:\"Count of Smaller Numbers After Self\",url:\"https://leetcode.com/problems/count-of-smaller-numbers-after-self/\",diff:\"Hard\",opt:\"O(n log n) time, O(n) space\",hint:\"Process right to left. Coordinate compress. Fenwick tree: query how many smaller seen so far, then update.\",algo:\"1. Coord compress. 2. Process right\u2192left. 3. ans[i]=BIT.query(rank-1). 4. BIT.update(rank,1).\"},\n    {name:\"Sliding Window Maximum\",url:\"https://leetcode.com/problems/sliding-window-maximum/\",diff:\"Hard\",opt:\"O(n) time, O(k) space\",hint:\"Monotonic decreasing deque of indices.\",algo:\"See Stacks & Queues section for full algorithm.\"},\n    {name:\"Shortest Subarray with Sum at Least K\",url:\"https://leetcode.com/problems/shortest-subarray-with-sum-at-least-k/\",diff:\"Hard\",opt:\"O(n) time, O(n) space\",hint:\"Prefix sums + monotonic increasing deque. Front satisfies K \u2192 record length + pop front. Back >= current \u2192 pop back.\",algo:\"1. prefix[i]=sum(nums[:i]). 2. Mono increasing deque. 3. For i: while dq and prefix[i]-prefix[dq[0]]>=K: ans=min(ans,i-dq.popleft()). While dq and prefix[i]<=prefix[dq[-1]]: dq.pop(). dq.append(i).\"}\n  ]}]},\n  {title:\"15 \u2014 Sorting Algorithms (Deep)\", level:\"MAANG Level\", count:10, sections:[{label:\"Merge Sort, Quick Sort, Counting Sort\",problems:[\n    {name:\"Sort an Array\",url:\"https://leetcode.com/problems/sort-an-array/\",diff:\"Medium\",opt:\"O(n log n) time, O(n) space\",hint:\"Implement merge sort or quicksort from scratch.\",algo:\"Merge sort: split to halves, sort each, merge. Merge: two pointers, take smaller, append remainder.\"},\n    {name:\"Sort Colors\",url:\"https://leetcode.com/problems/sort-colors/\",diff:\"Medium\",opt:\"O(n) time, O(1) space\",hint:\"Dutch National Flag. Three pointers: low,mid,high. Swap based on value.\",algo:\"low=mid=0, high=n-1. While mid<=high: if nums[mid]==0: swap(low,mid), low++,mid++. If ==1: mid++. If ==2: swap(mid,high), high--.\"},\n    {name:\"Largest Number\",url:\"https://leetcode.com/problems/largest-number/\",diff:\"Medium\",opt:\"O(n log n) time, O(n) space\",hint:\"Custom sort: compare a+b vs b+a as strings. Larger concatenation comes first.\",algo:\"Sort strs with key=cmp_to_key(lambda a,b: 1 if a+b<b+a else -1). Join. Handle all-zeros edge case.\"},\n    {name:\"Kth Largest Element in an Array\",url:\"https://leetcode.com/problems/kth-largest-element-in-an-array/\",diff:\"Medium\",opt:\"O(n log k) heap, O(n) quickselect avg\",hint:\"Quickselect: partition around pivot. If pivot position == k: done. Recurse on correct half.\",algo:\"Quickselect: partition. If pos==n-k: return nums[pos]. If pos>n-k: recurse left. Else: right.\"},\n    {name:\"Count of Smaller Numbers After Self\",url:\"https://leetcode.com/problems/count-of-smaller-numbers-after-self/\",diff:\"Hard\",opt:\"O(n log n) time\",hint:\"Modified merge sort: count inversions during merge step.\",algo:\"During merge of left+right halves: for each right element being placed before a left element, that left element has one more smaller-to-its-right.\"},\n    {name:\"Reverse Pairs\",url:\"https://leetcode.com/problems/reverse-pairs/\",diff:\"Hard\",opt:\"O(n log n) time, O(n) space\",hint:\"Modified merge sort. Before actual merge: count pairs where left[i]>2*right[j]. Two pointers on sorted halves.\",algo:\"In merge: before merging, count valid pairs with two pointers (no reset needed since both sorted). Then normal merge.\"},\n    {name:\"Maximum Gap\",url:\"https://leetcode.com/problems/maximum-gap/\",diff:\"Hard\",opt:\"O(n) time, O(n) space\",hint:\"Pigeonhole: max gap >= (max-min)/(n-1). Bucket size = floor value. Gap only between consecutive buckets.\",algo:\"Bucket each num. Track min+max per bucket. Max gap = max(curMin - prevMax) across non-empty consecutive buckets.\"},\n    {name:\"Custom Sort String\",url:\"https://leetcode.com/problems/custom-sort-string/\",diff:\"Medium\",opt:\"O(n+m) time, O(1) space\",hint:\"Freq count of s. Append each char in 'order' as many times as it appears. Append leftovers.\",algo:\"freq=Counter(s). res=''. For c in order: res+=c*freq[c], del freq[c]. Return res+''.join(c*freq[c] for c in freq).\"}\n  ]}]},\n  {title:\"16 \u2014 Intervals & Greedy\", level:\"MAANG Level\", count:8, sections:[{label:\"Intervals + Greedy\",problems:[\n    {name:\"Merge Intervals\",url:\"https://leetcode.com/problems/merge-intervals/\",diff:\"Medium\",opt:\"O(n log n) time, O(n) space\",hint:\"Sort by start. Walk: if current.start<=last.end \u2192 merge (max end). Else append new.\",algo:\"Sort. res=[intervals[0]]. For i in rest: if i[0]<=res[-1][1]: res[-1][1]=max(res[-1][1],i[1]). Else: res.append(i).\"},\n    {name:\"Non-overlapping Intervals\",url:\"https://leetcode.com/problems/non-overlapping-intervals/\",diff:\"Medium\",opt:\"O(n log n) time, O(1) space\",hint:\"Sort by END. Greedily keep intervals. Count removals.\",algo:\"Sort by end. lastEnd=-inf, count=0. For start,end: if start>=lastEnd: lastEnd=end. Else: count++. Return count.\"},\n    {name:\"Insert Interval\",url:\"https://leetcode.com/problems/insert-interval/\",diff:\"Medium\",opt:\"O(n) time, O(n) space\",hint:\"Three phases: add non-overlapping before, merge all overlapping, add remainder.\",algo:\"1. Add intervals ending before newInterval.start. 2. While overlap (start<=newInterval.end): merge. 3. Add newInterval. 4. Add rest.\"},\n    {name:\"Meeting Rooms II\",url:\"https://leetcode.com/problems/meeting-rooms-ii/\",diff:\"Medium\",opt:\"O(n log n) time, O(n) space\",hint:\"Separate+sort start and end times. Two pointers: new meeting before earliest end \u2192 new room. Else room freed.\",algo:\"starts,ends=sorted. i=j=rooms=maxRooms=0. While i<n: if starts[i]<ends[j]: rooms++,i++. Else: rooms--,j++. maxRooms=max(maxRooms,rooms). Return maxRooms.\"},\n    {name:\"Jump Game\",url:\"https://leetcode.com/problems/jump-game/\",diff:\"Medium\",opt:\"O(n) time, O(1) space\",hint:\"Track farthest reachable. If current index > farthest: stuck. Update farthest = max(farthest, i+nums[i]).\",algo:\"farthest=0. For i in range(n): if i>farthest: False. farthest=max(farthest,i+nums[i]). Return True.\"},\n    {name:\"Jump Game II\",url:\"https://leetcode.com/problems/jump-game-ii/\",diff:\"Medium\",opt:\"O(n) time, O(1) space\",hint:\"BFS-like: when you reach current boundary, you must jump. Track farthest reachable for next jump.\",algo:\"jumps=0, curEnd=0, farthest=0. For i in 0..n-2: farthest=max(farthest,i+nums[i]). If i==curEnd: jumps++, curEnd=farthest. Return jumps.\"},\n    {name:\"Gas Station\",url:\"https://leetcode.com/problems/gas-station/\",diff:\"Medium\",opt:\"O(n) time, O(1) space\",hint:\"If total gas>=total cost, solution exists. When running tank goes negative, reset start to next station.\",algo:\"If sum(gas)<sum(cost): return -1. total=cur=start=0. For i: diff=gas[i]-cost[i]. total+=diff, cur+=diff. If cur<0: start=i+1, cur=0. Return start.\"},\n    {name:\"Candy\",url:\"https://leetcode.com/problems/candy/\",diff:\"Hard\",opt:\"O(n) time, O(n) space\",hint:\"Two passes. L\u2192R: higher rating than left \u2192 left+1 candy. R\u2192L: higher than right \u2192 max(current, right+1).\",algo:\"candy=[1]*n. L\u2192R: if rating[i]>rating[i-1]: candy[i]=candy[i-1]+1. R\u2192L: if rating[i]>rating[i+1]: candy[i]=max(candy[i],candy[i+1]+1). Return sum(candy).\"}\n  ]}]},\n  {title:\"17 \u2014 Math & Number Theory\", level:\"MAANG Level\", count:6, sections:[{label:\"Math problems\",problems:[\n    {name:\"Greatest Common Divisor of Strings\",url:\"https://leetcode.com/problems/greatest-common-divisor-of-strings/\",diff:\"Easy\",opt:\"O(n+m) time\",hint:\"str1+str2==str2+str1 \u2192 GCD exists. Answer = prefix of length gcd(len1,len2).\",algo:\"If str1+str2!=str2+str1: return ''. Return str1[:gcd(len(str1),len(str2))].\"},\n    {name:\"Count Primes\",url:\"https://leetcode.com/problems/count-primes/\",diff:\"Medium\",opt:\"O(n log log n) time, O(n) space\",hint:\"Sieve of Eratosthenes. Mark multiples of each prime starting from i*i.\",algo:\"is_prime=[T]*(n). is_prime[0]=is_prime[1]=F. For i in 2..sqrt(n): if prime: mark i*i, i*i+i, ... as F. Return sum(is_prime).\"},\n    {name:\"Pow(x, n)\",url:\"https://leetcode.com/problems/powx-n/\",diff:\"Medium\",opt:\"O(log n) time\",hint:\"Fast exponentiation: n even \u2192 (x\u00b2)^(n/2). n odd \u2192 x * x^(n-1). Handle negative n.\",algo:\"If n<0: x=1/x, n=-n. If n==0: 1. If n%2==0: return pow(x*x,n//2). Else: return x*pow(x,n-1).\"},\n    {name:\"Pascal's Triangle\",url:\"https://leetcode.com/problems/pascals-triangle/\",diff:\"Easy\",opt:\"O(n\u00b2) time+space\",hint:\"Each row starts+ends with 1. Middle values = sum of two above.\",algo:\"res=[[1]]. For i in 1..n-1: row=[1]+[prev[j]+prev[j+1] for j in range(len(prev)-1)]+[1]. res.append(row).\"},\n    {name:\"Super Pow\",url:\"https://leetcode.com/problems/super-pow/\",diff:\"Medium\",opt:\"O(log b) time\",hint:\"a^(10b+d) = (a^10)^b * a^d. Process digits left to right.\",algo:\"MOD=1337. For d in b: result=modpow(result,10)*modpow(a,d)%MOD. Return result.\"},\n    {name:\"Unique Paths\",url:\"https://leetcode.com/problems/unique-paths/\",diff:\"Medium\",opt:\"O(m\u00b7n) time, O(n) space\",hint:\"dp[c] += dp[c-1] for each row. First row all 1s.\",algo:\"dp=[1]*cols. For row in 1..m-1: for col in 1..cols-1: dp[col]+=dp[col-1]. Return dp[-1].\"}\n  ]}]\n];\n\nlet solved = {};\n\nfunction loadSolved(){\n  try { solved = JSON.parse(localStorage.getItem('dsa_solved')||'{}'); } catch(e){ solved={}; }\n}\nfunction saveSolved(){\n  try { localStorage.setItem('dsa_solved', JSON.stringify(solved)); } catch(e){}\n}\nfunction makeKey(phaseIdx,secIdx,probIdx){ return `p${phaseIdx}_s${secIdx}_pr${probIdx}`; }\n\nfunction renderStats(){\n  let total=0,done=0;\n  PHASES.forEach((ph,pi)=>{\n    ph.sections.forEach((sec,si)=>{\n      sec.problems.forEach((_,ri)=>{\n        if(ph.count>1||(ph.sections[0].problems[0].name!=='(43 problems \u2014 load from full sheet)')){\n          total++;\n          if(solved[makeKey(pi,si,ri)]) done++;\n        }\n      });\n    });\n  });\n  const pct = total>0?Math.round(done/total*100):0;\n  document.getElementById('probStats').innerHTML =\n    `<div class=\"stat-chip\">Total <span>${total}</span></div>` +\n    `<div class=\"stat-chip\">Solved <span>${done}</span></div>` +\n    `<div class=\"stat-chip\">Remaining <span>${total-done}</span></div>` +\n    `<div class=\"stat-chip\">Progress <span>${pct}%</span></div>`;\n}\n\nfunction renderPhase(ph, pi){\n  const totalP = ph.sections.reduce((a,s)=>a+s.problems.length,0);\n  const doneP = ph.sections.reduce((a,s,si)=>a+s.problems.filter((_,ri)=>solved[makeKey(pi,si,ri)]).length,0);\n  const pct = totalP>0?Math.round(doneP/totalP*100):0;\n  \n  let html = `<div class=\"phase-header\" onclick=\"togglePhase('ph${pi}')\">\n    <div>\n      <span class=\"phase-title\">${ph.title}</span>\n      <div class=\"phase-progress\"><div class=\"phase-progress-fill\" style=\"width:${pct}%\"></div></div>\n    </div>\n    <div class=\"phase-meta\">\n      <span>${ph.level}</span>\n      <span style=\"color:#0E9384;font-weight:700\">${doneP}/${totalP}</span>\n      <span id=\"ph${pi}arr\">\u25b6</span>\n    </div>\n  </div>\n  <div class=\"phase-body\" id=\"ph${pi}\">`;\n\n  ph.sections.forEach((sec,si)=>{\n    html += `<div class=\"section-label\">${sec.label}</div>`;\n    sec.problems.forEach((prob,ri)=>{\n      const key = makeKey(pi,si,ri);\n      const isSolved = !!solved[key];\n      const diffClass = prob.diff==='Easy'?'diff-easy':prob.diff==='Medium'?'diff-medium':'diff-hard';\n      const num = pi*100 + si*10 + ri + 1;\n      html += `<div class=\"prob-row\" id=\"row_${key}\" data-phase=\"${pi}\" data-diff=\"${prob.diff}\" data-name=\"${prob.name.toLowerCase()}\">\n        <div class=\"prob-num\">#${ri+1}</div>\n        <div class=\"prob-main\">\n          <div class=\"prob-name\">${prob.url?`<a href=\"${prob.url}\" target=\"_blank\" rel=\"noopener\">${prob.name} \u2197</a>`:prob.name}</div>\n          <div class=\"prob-hints\">\n            <span class=\"hint-optimal\">\u2705 Optimal: ${prob.opt}</span>\n            <span class=\"hint-technique\" onclick=\"this.style.maxHeight=this.style.maxHeight?'':'200px'\">\ud83d\udd35 Hint: ${prob.hint}</span>\n            <span class=\"hint-algo\" onclick=\"toggleAlgo('algo_${key}')\">\ud83d\udfe0 Full Algorithm (reveal only if stuck)</span>\n            <div class=\"hint-algo-body\" id=\"algo_${key}\">${prob.algo}</div>\n          </div>\n        </div>\n        <div class=\"diff-badge ${diffClass}\">${prob.diff}</div>\n        <div></div>\n        <div class=\"prob-check\"><input type=\"checkbox\" ${isSolved?'checked':''} onchange=\"toggleSolved('${key}')\"></div>\n      </div>`;\n    });\n  });\n  html += '</div>';\n  return html;\n}\n\nfunction togglePhase(id){\n  const body = document.getElementById(id);\n  const arr = document.getElementById(id+'arr');\n  body.classList.toggle('open');\n  if(arr) arr.textContent = body.classList.contains('open')?'\u25bc':'\u25b6';\n}\n\nfunction toggleAlgo(id){\n  document.getElementById(id).classList.toggle('open');\n}\n\nfunction toggleSolved(key){\n  solved[key] = !solved[key];\n  if(!solved[key]) delete solved[key];\n  saveSolved();\n  renderStats();\n  updatePhaseProgress();\n}\n\nfunction updatePhaseProgress(){\n  PHASES.forEach((ph,pi)=>{\n    const totalP = ph.sections.reduce((a,s)=>a+s.problems.length,0);\n    const doneP = ph.sections.reduce((a,s,si)=>a+s.problems.filter((_,ri)=>solved[makeKey(pi,si,ri)]).length,0);\n    const pct = totalP>0?Math.round(doneP/totalP*100):0;\n    const fill = document.querySelector(`#ph${pi} ~ * .phase-progress-fill, .phase-header:nth-child(${pi+1}) .phase-progress-fill`);\n    // Update the phase header's progress bar\n    const headers = document.querySelectorAll('.phase-header');\n    if(headers[pi]){\n      const bar = headers[pi].querySelector('.phase-progress-fill');\n      if(bar) bar.style.width = pct+'%';\n      const cnt = headers[pi].querySelector('.phase-meta span:nth-child(2)');\n      if(cnt) cnt.textContent = `${doneP}/${totalP}`;\n    }\n  });\n}\n\nfunction filterProbs(){\n  const q = document.getElementById('probSearch').value.toLowerCase();\n  const diff = document.getElementById('diffFilter').value;\n  const phase = document.getElementById('phaseFilter').value;\n  const status = document.getElementById('statusFilter').value;\n  \n  document.querySelectorAll('.prob-row').forEach(row=>{\n    const name = row.dataset.name||'';\n    const d = row.dataset.diff||'';\n    const p = row.dataset.phase||'';\n    const key = row.id.replace('row_','');\n    const isSolved = !!solved[key];\n    \n    const matchQ = !q || name.includes(q);\n    const matchD = !diff || d===diff;\n    const matchP = phase==='' || p===phase;\n    const matchS = !status || (status==='solved'?isSolved:!isSolved);\n    \n    row.style.display = (matchQ&&matchD&&matchP&&matchS)?'':'none';\n  });\n}\n\nfunction resetAll(){\n  document.getElementById('probSearch').value='';\n  document.getElementById('diffFilter').value='';\n  document.getElementById('phaseFilter').value='';\n  document.getElementById('statusFilter').value='';\n  filterProbs();\n}\n\n// Init\nloadSolved();\nconst container = document.getElementById('probContainer');\ncontainer.innerHTML = PHASES.map((ph,pi)=>renderPhase(ph,pi)).join('');\nrenderStats();\n<\\/script>\n</main>\n",
});